/* ========================================================================== */
/* LOGIN PAGE STYLES */
/* ========================================================================== */

.login-container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto',
    'Oxygen', 'Ubuntu', 'Cantarell', sans-serif;
  padding: 20px;
}

.login-card {
  background: white;
  padding: 40px;
  border-radius: 12px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
  width: 100%;
  max-width: 420px;
}

.login-title {
  text-align: center;
  color: #333;
  margin: 0 0 30px 0;
  font-size: 32px;
  font-weight: 700;
  letter-spacing: -0.5px;
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin-bottom: 20px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-label {
  color: #555;
  font-weight: 600;
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.form-input {
  padding: 14px 16px;
  border: 2px solid #e0e0e0;
  border-radius: 8px;
  font-size: 15px;
  font-weight: 500;
  transition: all 0.3s ease;
  background-color: #fafafa;
}

.form-input:focus {
  outline: none;
  border-color: #667eea;
  background-color: #fff;
  box-shadow: 0 0 0 4px rgba(102, 126, 234, 0.1);
}

.form-input:disabled {
  background-color: #f0f0f0;
  cursor: not-allowed;
  opacity: 0.6;
}

.form-input::placeholder {
  color: #999;
}

.submit-button {
  padding: 14px 24px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 8px;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
  margin-top: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);
}

.submit-button:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(102, 126, 234, 0.6);
}

.submit-button:active:not(:disabled) {
  transform: translateY(0);
}

.submit-button:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

.signup-link-button {
  width: 100%;
  padding: 12px 16px;
  margin-top: 6px;
  border: 1px solid #cbd5e1;
  background: #fff;
  color: #334155;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
}

.signup-link-button:hover:not(:disabled) {
  background: #f8fafc;
}

.error-message {
  background-color: #ffebee;
  color: #d32f2f;
  padding: 14px 16px;
  border-radius: 8px;
  border-left: 4px solid #d32f2f;
  font-size: 14px;
  font-weight: 500;
  margin-bottom: 15px;
  animation: slideDown 0.3s ease;
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.test-credentials {
  background-color: #f0f4ff;
  padding: 16px 18px;
  border-radius: 8px;
  margin-top: 20px;
  font-size: 13px;
  color: #555;
  border-left: 4px solid #667eea;
  line-height: 1.6;
}

.test-credentials p {
  margin: 6px 0;
  font-family: 'Courier New', monospace;
}

.test-credentials strong {
  color: #333;
  font-weight: 600;
}

.test-credentials hr {
  border: none;
  border-top: 1px solid #d0d8ff;
  margin: 10px 0;
}

/* ========================================================================== */
/* RESPONSIVE DESIGN */
/* ========================================================================== */

@media (max-width: 600px) {
  .login-card {
    margin: 20px;
    padding: 30px 20px;
  }

  .login-title {
    font-size: 28px;
    margin-bottom: 25px;
  }

  .form-input,
  .submit-button {
    font-size: 16px;
    padding: 12px 14px;
  }

  .test-credentials {
    font-size: 12px;
  }
}

@media (max-width: 400px) {
  .login-card {
    padding: 25px 15px;
  }

  .login-title {
    font-size: 24px;
    margin-bottom: 20px;
  }

  .form-label {
    font-size: 13px;
  }

  .form-input,
  .submit-button {
    font-size: 15px;
    padding: 12px 12px;
  }
}

/* ========================================================================== */
/* LOGIN PAGE — Pharmacy Design (Vert Vif + Blanc)                           */
/* ========================================================================== */

/* ── Fonts ─────────────────────────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

/* ── Root palette ──────────────────────────────────────────────────────── */
:root {
  --ph-green:       #00A651;
  --ph-green-dark:  #007A3A;
  --ph-green-deep:  #00572A;
  --ph-green-light: #E6F7EE;
  --ph-green-mid:   #C2EAD4;
  --ph-accent:      #34C97D;
  --ph-white:       #FFFFFF;
  --ph-off-white:   #F4FAF7;
  --ph-text-dark:   #0F2318;
  --ph-text-mid:    #3D5A46;
  --ph-text-light:  #7A9485;
  --ph-border:      #D1E8DB;
  --ph-error:       #E53935;
  --ph-error-bg:    #FFF0EF;
  --ph-shadow:      rgba(0, 87, 42, 0.12);
}

/* ── Layout ────────────────────────────────────────────────────────────── */
.login-container {
  display: flex;
  min-height: 100vh;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: var(--ph-off-white);
}

/* ── Left branding panel ────────────────────────────────────────────────── */
.login-brand-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  padding: 60px 48px;
  background: linear-gradient(160deg, var(--ph-green-deep) 0%, var(--ph-green-dark) 45%, var(--ph-green) 100%);
  position: relative;
  overflow: hidden;
}

/* decorative blobs */
.login-brand-panel::before {
  content: '';
  position: absolute;
  top: -80px;
  right: -80px;
  width: 280px;
  height: 280px;
  border-radius: 50%;
  background: rgba(255,255,255,0.06);
}
.login-brand-panel::after {
  content: '';
  position: absolute;
  bottom: -60px;
  left: -60px;
  width: 220px;
  height: 220px;
  border-radius: 50%;
  background: rgba(255,255,255,0.05);
}

.login-brand-cross {
  width: 80px;
  height: 80px;
  border-radius: 22px;
  background: rgba(255,255,255,0.15);
  border: 2px solid rgba(255,255,255,0.3);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 42px;
  margin-bottom: 32px;
  backdrop-filter: blur(8px);
  position: relative;
  z-index: 1;
}

.login-brand-title {
  font-size: 36px;
  font-weight: 800;
  color: var(--ph-white);
  text-align: center;
  letter-spacing: -0.5px;
  position: relative;
  z-index: 1;
  margin-bottom: 12px;
}

.login-brand-subtitle {
  font-size: 14px;
  font-weight: 400;
  color: rgba(255,255,255,0.65);
  text-align: center;
  line-height: 1.6;
  max-width: 260px;
  position: relative;
  z-index: 1;
  margin-bottom: 48px;
}

.login-brand-features {
  display: flex;
  flex-direction: column;
  gap: 16px;
  width: 100%;
  max-width: 280px;
  position: relative;
  z-index: 1;
}

.login-brand-feature {
  display: flex;
  align-items: center;
  gap: 12px;
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: 12px;
  padding: 14px 16px;
}

.login-brand-feature-icon {
  font-size: 20px;
  flex-shrink: 0;
}

.login-brand-feature-text {
  font-size: 13px;
  color: rgba(255,255,255,0.85);
  font-weight: 500;
}

/* ── Right form panel ───────────────────────────────────────────────────── */
.login-form-panel {
  width: 480px;
  min-width: 420px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 60px 56px;
  background: var(--ph-white);
  box-shadow: -4px 0 40px rgba(0,0,0,0.06);
}

.login-card {
  width: 100%;
  max-width: 360px;
}

/* ── Card header ────────────────────────────────────────────────────────── */
.login-header-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--ph-green-light);
  color: var(--ph-green-dark);
  font-size: 12px;
  font-weight: 600;
  padding: 5px 12px;
  border-radius: 20px;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  margin-bottom: 20px;
}

.login-title {
  font-size: 26px;
  font-weight: 800;
  color: var(--ph-text-dark);
  margin: 0 0 6px;
  letter-spacing: -0.5px;
}

.login-sub {
  font-size: 14px;
  color: var(--ph-text-light);
  margin: 0 0 32px;
}

/* ── Form elements ──────────────────────────────────────────────────────── */
.login-form {
  display: flex;
  flex-direction: column;
  gap: 18px;
  margin-bottom: 16px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.form-label {
  color: var(--ph-text-dark);
  font-weight: 600;
  font-size: 13px;
  letter-spacing: 0.2px;
}

.form-input-wrapper {
  position: relative;
}

.form-input-icon {
  position: absolute;
  left: 14px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 16px;
  pointer-events: none;
}

.form-input {
  width: 100%;
  padding: 13px 14px 13px 42px;
  border: 1.5px solid var(--ph-border);
  border-radius: 10px;
  font-size: 14.5px;
  font-weight: 500;
  font-family: inherit;
  color: var(--ph-text-dark);
  background: var(--ph-off-white);
  transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
  box-sizing: border-box;
}

.form-input:focus {
  outline: none;
  border-color: var(--ph-green);
  background: var(--ph-white);
  box-shadow: 0 0 0 4px rgba(0,166,81,0.12);
}

.form-input:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.form-input::placeholder {
  color: var(--ph-text-light);
  font-weight: 400;
}

/* ── Submit button ──────────────────────────────────────────────────────── */
.submit-button {
  width: 100%;
  padding: 14px 24px;
  background: linear-gradient(135deg, var(--ph-green-dark) 0%, var(--ph-green) 100%);
  color: var(--ph-white);
  border: none;
  border-radius: 10px;
  font-size: 15px;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.25s;
  margin-top: 6px;
  letter-spacing: 0.3px;
  box-shadow: 0 4px 20px rgba(0,166,81,0.35);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
}

.submit-button:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 8px 28px rgba(0,166,81,0.45);
  background: linear-gradient(135deg, var(--ph-green-deep) 0%, var(--ph-green-dark) 100%);
}

.submit-button:active:not(:disabled) {
  transform: translateY(0);
  box-shadow: 0 2px 10px rgba(0,166,81,0.3);
}

.submit-button:disabled {
  opacity: 0.65;
  cursor: not-allowed;
}

/* spinner */
.btn-spinner {
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255,255,255,0.35);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ── Divider ────────────────────────────────────────────────────────────── */
.login-divider {
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 20px 0 16px;
}
.login-divider::before,
.login-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--ph-border);
}
.login-divider span {
  font-size: 12px;
  color: var(--ph-text-light);
  white-space: nowrap;
}

/* ── Signup link button ─────────────────────────────────────────────────── */
.signup-link-button {
  width: 100%;
  padding: 13px 16px;
  border: 1.5px solid var(--ph-border);
  background: var(--ph-white);
  color: var(--ph-green-dark);
  border-radius: 10px;
  font-size: 14px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
}

.signup-link-button:hover:not(:disabled) {
  background: var(--ph-green-light);
  border-color: var(--ph-green-mid);
  color: var(--ph-green-deep);
}

.signup-link-button:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

/* ── Error message ──────────────────────────────────────────────────────── */
.error-message {
  background: var(--ph-error-bg);
  color: var(--ph-error);
  padding: 12px 14px;
  border-radius: 10px;
  border-left: 4px solid var(--ph-error);
  font-size: 13.5px;
  font-weight: 500;
  margin-bottom: 18px;
  display: flex;
  align-items: center;
  gap: 8px;
  animation: slideDown 0.25s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ── Footer note ────────────────────────────────────────────────────────── */
.login-footer-note {
  margin-top: 28px;
  text-align: center;
  font-size: 12px;
  color: var(--ph-text-light);
}

.login-footer-note a {
  color: var(--ph-green-dark);
  text-decoration: none;
  font-weight: 500;
}

/* ── Responsive ─────────────────────────────────────────────────────────── */
@media (max-width: 900px) {
  .login-brand-panel {
    display: none;
  }
  .login-form-panel {
    width: 100%;
    min-width: unset;
    padding: 40px 24px;
    box-shadow: none;
  }
}

@media (max-width: 480px) {
  .login-form-panel {
    padding: 32px 20px;
  }
  .login-title {
    font-size: 22px;
  }
}

// ============================================================================
// ADMIN CONTROLLER
// ============================================================================
// Handles admin operations: user creation, listing, status management

const bcryptjs = require('bcryptjs');
const userModel = require('../models/user.model');

// ============================================================================
// Create parent user (admin only)
// ============================================================================
// POST /admin/create-parent
// Body: { name, email }
// Note: Password is NULL, parent sets it via setPassword endpoint
const createParent = async (req, res) => {
  try {
    const { name, email } = req.body;

    // Validate input
    if (!name || !email) {
      return res.status(400).json({
        success: false,
        message: 'Name and email are required',
      });
    }

    // Check if user already exists
    const existingUser = await userModel.findByEmail(email);
    if (existingUser) {
      return res.status(400).json({
        success: false,
        message: 'User with this email already exists',
      });
    }

    // Create parent with NULL password
    const userId = await userModel.createUser(name, email, null, 'parent');

    res.status(201).json({
      success: true,
      message: 'Parent created successfully',
      data: {
        id: userId,
        name,
        email,
        role: 'parent',
        password: null,
      },
    });
  } catch (error) {
    console.error('Create parent error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to create parent',
      error: error.message,
    });
  }
};

// ============================================================================
// Create professional user (admin only)
// ============================================================================
// POST /admin/create-professional
// Body: { name, email, password }
const createProfessional = async (req, res) => {
  try {
    const { name, email, password } = req.body;

    // Validate input
    if (!name || !email || !password) {
      return res.status(400).json({
        success: false,
        message: 'Name, email, and password are required',
      });
    }

    // Validate password strength
    if (password.length < 6) {
      return res.status(400).json({
        success: false,
        message: 'Password must be at least 6 characters',
      });
    }

    // Check if user already exists
    const existingUser = await userModel.findByEmail(email);
    if (existingUser) {
      return res.status(400).json({
        success: false,
        message: 'User with this email already exists',
      });
    }

    // Hash password with bcryptjs
    const saltRounds = 10;
    const hashedPassword = await bcryptjs.hash(password, saltRounds);

    // Create professional
    const userId = await userModel.createUser(name, email, hashedPassword, 'professional');

    res.status(201).json({
      success: true,
      message: 'Professional created successfully',
      data: {
        id: userId,
        name,
        email,
        role: 'professional',
      },
    });
  } catch (error) {
    console.error('Create professional error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to create professional',
      error: error.message,
    });
  }
};

// ============================================================================
// List all users with optional filters
// ============================================================================
// GET /admin/users
// Query params: role, is_active
const listUsers = async (req, res) => {
  try {
    const filters = {};

    if (req.query.role) {
      filters.role = req.query.role;
    }

    if (req.query.is_active !== undefined) {
      filters.is_active = req.query.is_active === 'true' ? 1 : 0;
    }

    const users = await userModel.getAllUsers(filters);

    res.status(200).json({
      success: true,
      message: 'Users retrieved successfully',
      data: users,
    });
  } catch (error) {
    console.error('List users error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to list users',
      error: error.message,
    });
  }
};

// ============================================================================
// Toggle user active/inactive status
// ============================================================================
// PUT /admin/toggle-active/:id
// Body: { is_active }
const toggleUserActive = async (req, res) => {
  try {
    const { id } = req.params;
    const { is_active } = req.body;

    // Validate input
    if (is_active === undefined) {
      return res.status(400).json({
        success: false,
        message: 'is_active is required',
      });
    }

    // Verify user exists
    const user = await userModel.findById(id);
    if (!user) {
      return res.status(404).json({
        success: false,
        message: 'User not found',
      });
    }

    // Prevent admin from deactivating themselves
    if (user.id === req.user.id && !is_active) {
      return res.status(400).json({
        success: false,
        message: 'Cannot deactivate your own account',
      });
    }

    await userModel.setActiveStatus(id, is_active);

    res.status(200).json({
      success: true,
      message: 'User status updated successfully',
      data: {
        id,
        is_active,
      },
    });
  } catch (error) {
    console.error('Toggle user active error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to toggle user status',
      error: error.message,
    });
  }
};

// ============================================================================
// Get dashboard statistics (admin only)
// ============================================================================
// GET /admin/stats
const getStats = async (req, res) => {
  try {
    const allUsers = await userModel.getAllUsers();
    const parents = allUsers.filter((u) => u.role === 'parent');
    const professionals = allUsers.filter((u) => u.role === 'professional');
    const admins = allUsers.filter((u) => u.role === 'admin');

    res.status(200).json({
      success: true,
      message: 'Statistics retrieved successfully',
      data: {
        total_users: allUsers.length,
        total_parents: parents.length,
        total_professionals: professionals.length,
        total_admins: admins.length,
        active_users: allUsers.filter((u) => u.is_active).length,
      },
    });
  } catch (error) {
    console.error('Get stats error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to get statistics',
      error: error.message,
    });
  }
};

module.exports = {
  createParent,
  createProfessional,
  listUsers,
  toggleUserActive,
  getStats,
};

