// POST /content/upload
// Admin only - Upload media file for content
const uploadContent = async (req, res) => {
  try {
    // Check if file was uploaded
    if (!req.file) {
      return res.status(400).json({
        success: false,
        message: 'No file uploaded',
      });
    }

    const {
      title,
      type,
      category,
      category_color,
      emoji,
      duration,
      steps,
      minutes,
      emoji_color,
      age_group,
      level,
      description,
    } = req.body;

    // Validate required fields
    if (!title || !type) {
      return res.status(400).json({
        success: false,
        message: 'Title and type are required',
      });
    }

    // Validate type enum
    if (!['video', 'activity', 'audio'].includes(type)) {
      return res.status(400).json({
        success: false,
        message: 'Type must be "video", "audio", or "activity"',
      });
    }

    // Build file URL
    const fileUrl = `/uploads/${req.file.filename}`;

    // Create content with all fields including new ones
    const contentId = await contentModel.createWithAllFields(
      title,
      type,
      category,
      category_color,
      emoji,
      duration,
      steps,
      minutes,
      emoji_color,
      age_group,
      level,
      fileUrl,
      description
    );

    res.status(201).json({
      success: true,
      message: 'Content uploaded successfully',
      data: {
        id: contentId,
        title,
        type,
        category,
        category_color,
        emoji,
        duration,
        steps,
        minutes,
        emoji_color,
        age_group,
        level,
        url: fileUrl,
        description,
        filename: req.file.filename,
        size: req.file.size,
      },
    });
  } catch (error) {
    console.error('Upload content error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to upload content',
      error: error.message,
    });
  }
};

module.exports = {
  getAll,
  getById,
  create,
  update,
  deleteContent,
  uploadContent,
};

