// ============================================================================
// VIDEO CARD COMPONENT
// ============================================================================

function VideoCard({ video }: { video: Video }): JSX.Element {
  const [hovered, setHovered] = useState(false);
  const mediaUrl = getMediaUrl(video.url);

  const handleWatch = () => {
    if (!mediaUrl) return;
    window.open(mediaUrl, '_blank', 'noopener,noreferrer');
  };

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: '#fff',
        borderRadius: 20,
        overflow: 'hidden',
        boxShadow: hovered
          ? '0 8px 32px rgba(56,178,172,0.18)'
          : '0 2px 12px rgba(0,0,0,0.06)',
        transition: 'box-shadow 0.25s, transform 0.25s',
        transform: hovered ? 'translateY(-4px)' : 'none',
        display: 'flex',
        flexDirection: 'column',
        minWidth: 0,
        cursor: 'pointer',
      } as React.CSSProperties}
    >
      {/* Thumbnail / Video preview */}
      <div
        style={{
          background: 'linear-gradient(135deg, #e0f7fa 0%, #b2ebf2 100%)',
          height: 160,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: 64,
          overflow: 'hidden',
        }}
      >
        {mediaUrl ? (
          <video
            src={mediaUrl}
            controls
            preload="metadata"
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        ) : (
          video.emoji
        )}
      </div>

      {/* Info */}
      <div style={{ padding: '14px 16px 16px' }}>
        <p
          style={{
            margin: '0 0 10px',
            fontWeight: 700,
            fontSize: 15,
            color: '#1e3a5f',
            lineHeight: 1.3,
            minHeight: 40,
          }}
        >
          {video.title}
        </p>

        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 12,
            marginBottom: 14,
          }}
        >
          <span
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 4,
              fontSize: 12,
              color: '#64748b',
            }}
          >
            <span style={{ fontSize: 13 }}></span>
            {video.category}
          </span>
          <span
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 4,
              fontSize: 12,
              color: '#64748b',
            }}
          >
            <span style={{ fontSize: 13 }}>⏱️</span>
            {video.duration}
          </span>
        </div>

        <button
          type="button"
          onClick={handleWatch}
          disabled={!mediaUrl}
          style={{
            width: '100%',
            padding: '11px 0',
            borderRadius: 10,
            border: 'none',
            background: 'linear-gradient(90deg, #38b2ac 0%, #2dd4bf 100%)',
            color: '#fff',
            fontWeight: 700,
            fontSize: 15,
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 8,
            letterSpacing: 0.3,
            opacity: mediaUrl ? 1 : 0.6,
          }}
        >
          {mediaUrl ? '▶ Regarder' : '⏳ Vidéo indisponible'}
        </button>
      </div>
    </div>
  );
}

