            onClick={logout}
            style={{
              padding: '10px 20px',
              background: 'linear-gradient(90deg, #ef4444 0%, #dc2626 100%)',
              color: '#fff',
              border: 'none',
              borderRadius: 50,
              fontWeight: 700,
              fontSize: 15,
              cursor: 'pointer',
            }}
          >
            Déconnexion
          </button>
        </div>
      </header>

      {/* ── LOADING STATE ── */}
      {loading && (
        <div
          style={{
            padding: '40px',
            textAlign: 'center',
            color: '#1e3a5f',
            fontSize: 18,
            fontWeight: 700,
          }}
        >
          ⏳ Chargement du contenu...
        </div>
      )}

      {/* ── MAIN CONTENT ── */}
      {!loading && (
        <main style={{ padding: '0 40px', position: 'relative', zIndex: 1 }}>
          {/* Videos Section */}
          {videos.length > 0 && (
            <section style={{ marginBottom: 44 }}>
              <h2
                style={{
                  fontSize: 20,
                  fontWeight: 800,
                  color: '#1e3a5f',
                  margin: '0 0 20px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                }}
              >
                 Vidéos pour toi
              </h2>

              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: 20,
                }}
              >
                {videos.map((v) => (
                  <VideoCard key={v.id} video={v} />
                ))}
              </div>
            </section>
          )}

          {/* Activities Section */}
          {activities.length > 0 && (
            <section>
              <h2
                style={{
                  fontSize: 20,
                  fontWeight: 800,
                  color: '#1e3a5f',
                  margin: '0 0 20px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                }}
              >
                 Mes activités
              </h2>

              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
                  gap: 20,
                }}
              >
                {activities.map((a) => (
                  <ActivityCard key={a.id} activity={a} />
                ))}
              </div>
            </section>
          )}

          {/* Empty State */}
          {!loading && videos.length === 0 && activities.length === 0 && (
            <div
              style={{
                padding: '40px',
                textAlign: 'center',
                color: '#64748b',
                fontSize: 18,
              }}
            >
              <p>Aucun contenu disponible pour le moment. </p>
              <p style={{ fontSize: 14, marginTop: 10 }}>Revenez bientôt pour découvrir de nouvelles vidéos et activités!</p>
            </div>
          )}
        </main>
      )}
    </div>
  );
};

// ============================================================================
// CHILD DASHBOARD — Espace enfant AIDAA
// ============================================================================
// 4 Modules : A-Bibliothèque | B-Séquences | C-AAC | D-Jeux
// Filtrage par participant_category + activity logging médical

import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../features/auth/hooks/useAuth';
import { Video, Activity } from '../features/content/types/content.types';
import { MemoryGame } from '../features/games/MemoryGame';
import { ColorMatchGame } from '../features/games/ColorMatchGame';
import api from '../lib/api';

const BACKEND_BASE = 'http://localhost:5000';

// ── Helpers ─────────────────────────────────────────────────────────────────
const buildMediaUrl = (url?: string): string | null => {
  if (!url) return null;
  return url.startsWith('http') ? url : `${BACKEND_BASE}${url.startsWith('/') ? '' : '/'}${url}`;
};

// ── Types ────────────────────────────────────────────────────────────────────
interface Stats   { total_points: number; total_activities: number }
interface Badge   { id: number; name: string; emoji: string; color: string }
interface Sequence {
  id: number; title: string; description: string; emoji: string;
  duration_minutes: number; difficulty: string; steps?: SeqStep[];
}
interface SeqStep {
  id: number; step_number: number; title: string; description: string;
  emoji: string; duration_seconds: number;
}
interface AACSymbol { id: number; label: string; emoji: string; category: string; color: string }

const CAT_CONFIG = {
  enfant: { label: 'Enfant', emoji: '', color: '#10b981' },
  jeune:  { label: 'Jeune',  emoji: '', color: '#3b82f6' },
  adulte: { label: 'Adulte', emoji: '', color: '#8b5cf6' },
};

// ============================================================================
// SEQUENCE VIEWER MODAL — Module B
// ============================================================================
function SequenceViewer({ sequence, onClose, onComplete }: {
  sequence: Sequence;
  onClose: () => void;
  onComplete: (score: number, dur: number) => void;
}): JSX.Element {
  const [step, setStep]   = useState(0);
  const [done, setDone]   = useState(false);
  const startRef          = useRef(Date.now());
  const steps             = sequence.steps ?? [];
  const totalSteps        = steps.length;
  const current           = steps[step];
  const progressPct       = totalSteps > 0 ? (step / totalSteps) * 100 : 0;

  const handleNext = () => {
    if (step < totalSteps - 1) {
      setStep((s) => s + 1);
    } else {
      setDone(true);
      onComplete(totalSteps * 10, Math.round((Date.now() - startRef.current) / 1000));
    }
  };

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 900, background: 'rgba(15,35,24,0.88)', backdropFilter: 'blur(6px)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
      <div style={{ background: '#fff', borderRadius: 24, padding: '28px 28px 32px', maxWidth: 500, width: '100%', boxShadow: '0 24px 80px rgba(0,0,0,0.3)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <div>
            <h2 style={{ margin: 0, fontSize: 20, fontWeight: 800, color: '#1e3a5f' }}>{sequence.emoji} {sequence.title}</h2>
            <p style={{ margin: '4px 0 0', fontSize: 13, color: '#64748b' }}>{totalSteps} étapes • {sequence.duration_minutes} min</p>
          </div>
          <button onClick={onClose} style={{ background: '#f1f5f9', border: 'none', borderRadius: 10, width: 36, height: 36, cursor: 'pointer', fontSize: 18, color: '#64748b' }}>✕</button>
        </div>
        <div style={{ background: '#f1f5f9', borderRadius: 8, height: 10, marginBottom: 24, overflow: 'hidden' }}>
          <div style={{ height: '100%', background: 'linear-gradient(90deg,#10b981,#34d399)', width: `${progressPct}%`, borderRadius: 8, transition: 'width 0.4s' }} />
        </div>
        {!done && current ? (
          <>
            <div style={{ textAlign: 'center', marginBottom: 20 }}>
              <div style={{ display: 'inline-block', background: '#f0fdf4', color: '#065f46', borderRadius: 20, padding: '4px 14px', fontSize: 12, fontWeight: 700, marginBottom: 16 }}>
                Étape {step + 1} / {totalSteps}
              </div>
              <div style={{ width: 90, height: 90, borderRadius: '50%', background: 'linear-gradient(135deg,#d1fae5,#a7f3d0)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 44, margin: '0 auto 16px', boxShadow: '0 4px 20px rgba(16,185,129,0.25)' }}>
                {current.emoji}
              </div>
              <h3 style={{ margin: '0 0 10px', fontSize: 22, fontWeight: 800, color: '#1e3a5f' }}>{current.title}</h3>
              <p style={{ margin: 0, fontSize: 15, color: '#475569', lineHeight: 1.6 }}>{current.description}</p>
            </div>
            <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
              {step > 0 && (
                <button onClick={() => setStep((s) => s - 1)} style={{ flex: 1, padding: '13px 0', borderRadius: 12, border: '2px solid #e2e8f0', background: '#fff', color: '#1e3a5f', fontWeight: 700, fontSize: 15, cursor: 'pointer' }}>
                  ← Précédent
                </button>
              )}
              <button onClick={handleNext} style={{ flex: 2, padding: '13px 0', borderRadius: 12, border: 'none', background: 'linear-gradient(135deg,#10b981,#34d399)', color: '#fff', fontWeight: 700, fontSize: 15, cursor: 'pointer', boxShadow: '0 4px 16px rgba(16,185,129,0.35)' }}>
                {step < totalSteps - 1 ? 'Suivant →' : '✅ Terminer !'}
              </button>
            </div>
          </>
        ) : done ? (
          <div style={{ textAlign: 'center', padding: '16px 0 8px' }}>
            <div style={{ fontSize: 56 }}></div>
            <h3 style={{ margin: '12px 0 8px', fontSize: 22, fontWeight: 800, color: '#065f46' }}>Bravo ! Séquence terminée !</h3>
            <p style={{ margin: '0 0 20px', fontSize: 14, color: '#059669' }}>Tu as gagné {totalSteps * 10} points !</p>
            <button onClick={onClose} style={{ padding: '13px 32px', borderRadius: 12, border: 'none', background: 'linear-gradient(135deg,#10b981,#34d399)', color: '#fff', fontWeight: 700, fontSize: 15, cursor: 'pointer' }}>
              Retour 
            </button>
          </div>
        ) : (
          <p style={{ textAlign: 'center', color: '#64748b' }}>Aucune étape disponible</p>
        )}
      </div>
    </div>
  );
}

// ============================================================================
// MAIN CHILD DASHBOARD
// ============================================================================
export const ChildDashboard = (): JSX.Element => {
  const { logout } = useAuth();
  const navigate   = useNavigate();

  const childId   = parseInt(localStorage.getItem('selected_child_id') ?? '0', 10);
  const childName = localStorage.getItem('selected_child_name') ?? 'Participant';
  const childCat  = (localStorage.getItem('selected_child_category') ?? 'enfant') as 'enfant' | 'jeune' | 'adulte';
  const catCfg    = CAT_CONFIG[childCat] ?? CAT_CONFIG.enfant;

  // ── State ────────────────────────────────────────────────────────────────
  const [activeTab, setActiveTab] = useState<'library' | 'sequences' | 'aac' | 'games'>('library');
  const [videos,     setVideos]     = useState<Video[]>([]);
  const [activities, setActivities] = useState<Activity[]>([]);
  const [loadingLib, setLoadingLib] = useState(true);
  const [sequences,      setSequences]      = useState<Sequence[]>([]);
  const [loadingSeq,     setLoadingSeq]     = useState(false);
  const [activeSequence, setActiveSequence] = useState<Sequence | null>(null);
  const [aacSymbols,     setAACSymbols]     = useState<AACSymbol[]>([]);
  const [aacCategories,  setAACCategories]  = useState<string[]>([]);
  const [activeAACCat,   setActiveAACCat]   = useState<string>('Besoins');
  const [aacPhrase,      setAACPhrase]      = useState<AACSymbol[]>([]);
  const [loadingAAC,     setLoadingAAC]     = useState(false);
  const [activeGame,     setActiveGame]     = useState<'memory' | 'color' | null>(null);
  const [stats,  setStats]  = useState<Stats>({ total_points: 0, total_activities: 0 });
  const [badges, setBadges] = useState<Badge[]>([]);

  // ── Data fetching ────────────────────────────────────────────────────────
  const fetchStats = useCallback(async () => {
    if (!childId) return;
    try {
      const [s, b] = await Promise.all([
        api.get(`/api/gamification/${childId}/stats`),
        api.get(`/api/gamification/${childId}/badges`),
      ]);
      if (s.data.success) setStats(s.data.data);
      if (b.data.success) setBadges(b.data.data);
    } catch { /* silently ignore */ }
  }, [childId]);

  useEffect(() => {
    const loadLib = async () => {
      setLoadingLib(true);
      try {
        const [vRes, aRes] = await Promise.all([
          api.get(`/api/content?type=video&participant_category=${childCat}`),
          api.get(`/api/content?type=activity&participant_category=${childCat}`),
        ]);
        if (vRes.data.success) setVideos(vRes.data.data ?? []);
        if (aRes.data.success) setActivities(aRes.data.data ?? []);
      } catch (e) { console.error('Library load error', e); }
      finally { setLoadingLib(false); }
    };
    loadLib();
    fetchStats();
  }, [childCat, fetchStats]);

  useEffect(() => {
    if (activeTab !== 'sequences' || sequences.length > 0) return;
    const load = async () => {
      setLoadingSeq(true);
      try {
        const res = await api.get(`/api/sequences?category=${childCat}`);
        if (res.data.success) setSequences(res.data.data ?? []);
      } catch (e) { console.error('Sequences error', e); }
      finally { setLoadingSeq(false); }
    };
    load();
  }, [activeTab, childCat, sequences.length]);

  useEffect(() => {
    if (activeTab !== 'aac' || aacSymbols.length > 0) return;
    const load = async () => {
      setLoadingAAC(true);
      try {
        const [symRes, catRes] = await Promise.all([
          api.get(`/api/aac/symbols?participant_category=${childCat}`),
          api.get('/api/aac/categories'),
        ]);
        if (symRes.data.success) setAACSymbols(symRes.data.data ?? []);
        if (catRes.data.success) {
          const cats: string[] = catRes.data.data ?? [];
          setAACCategories(cats);
          if (cats.length > 0) setActiveAACCat(cats[0]);
        }
      } catch (e) { console.error('AAC error', e); }
      finally { setLoadingAAC(false); }
    };
    load();
  }, [activeTab, childCat, aacSymbols.length]);

  // ── Logging helpers ───────────────────────────────────────────────────────
  const logActivity = useCallback(async (contentId: number, action: string, score = 0, duration = 0) => {
    if (!childId) return;
    try {
      await api.post('/api/activity-log', { childId, contentId, status: score > 0 ? 'completed' : 'started', score, duration_seconds: duration, action });
      setStats((p) => ({ total_points: p.total_points + score, total_activities: p.total_activities + 1 }));
    } catch (e) { console.error('Log activity error', e); }
  }, [childId]);

  const logGameScore = useCallback(async (gameId: number | string, score: number, duration: number) => {
    if (!childId) return;
    try {
      const res = await api.post(`/api/gamification/${childId}/score`, { gameId, score, duration_seconds: duration });
      if (res.data.newBadges?.length > 0) setBadges((p) => [...p, ...res.data.newBadges]);
      setStats((p) => ({ total_points: p.total_points + score, total_activities: p.total_activities + 1 }));
    } catch (e) { console.error('Log game error', e); }
  }, [childId]);

  // ── Sequence handling ─────────────────────────────────────────────────────
  const openSequence = async (seq: Sequence) => {
    if (seq.steps) { setActiveSequence(seq); return; }
    try {
      const res = await api.get(`/api/sequences/${seq.id}`);
      if (res.data.success) setActiveSequence(res.data.data);
    } catch (e) { console.error('Sequence fetch error', e); }
  };

  // ── AAC speech synthesis ──────────────────────────────────────────────────
  const speak = (text: string) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utt = new SpeechSynthesisUtterance(text);
    utt.lang = 'fr-FR'; utt.rate = 0.85;
    window.speechSynthesis.speak(utt);
  };

  // ── Tab button style ──────────────────────────────────────────────────────
  const tabStyle = (tab: string): React.CSSProperties => ({
    flex: 1, padding: '11px 4px', border: 'none', cursor: 'pointer',
    borderRadius: 10, fontWeight: 700, fontSize: 12, transition: 'all 0.2s',
    background: activeTab === tab ? catCfg.color : '#fff',
    color: activeTab === tab ? '#fff' : '#64748b',
    boxShadow: activeTab === tab ? `0 4px 14px ${catCfg.color}44` : 'none',
  });

  // ============================================================================
  // RENDER
  // ============================================================================
  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(160deg,#eef6fb 0%,#e8f4f8 60%,#ede9f6 100%)', fontFamily: "'Nunito','Quicksand','Segoe UI',sans-serif", paddingBottom: 48 }}>

      {/* ── HEADER ─────────────────────────────────────────────────────────── */}
      <header style={{ background: '#fff', boxShadow: '0 2px 16px rgba(0,0,0,0.07)', padding: '14px 28px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 10 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
          <div style={{ width: 50, height: 50, borderRadius: '50%', background: `linear-gradient(135deg,${catCfg.color},${catCfg.color}99)`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, boxShadow: `0 4px 14px ${catCfg.color}44` }}>
            {catCfg.emoji}
          </div>
          <div>
            <h1 style={{ margin: 0, fontSize: 19, fontWeight: 800, color: '#1e3a5f' }}>Bonjour {childName} </h1>
            <span style={{ background: `${catCfg.color}18`, color: catCfg.color, borderRadius: 20, padding: '2px 10px', fontSize: 11, fontWeight: 700 }}>
              {catCfg.emoji} {catCfg.label}
            </span>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <div style={{ background: '#fff7ed', borderRadius: 20, padding: '7px 14px', fontWeight: 700, color: '#f97316', fontSize: 13 }}>⭐ {stats.total_points} pts</div>
          <div style={{ background: '#f0f9ff', borderRadius: 20, padding: '7px 14px', fontWeight: 700, color: '#0284c7', fontSize: 13 }}> {badges.length} badges</div>
          <button onClick={() => navigate('/child-selection')} style={{ padding: '8px 14px', background: '#f1f5f9', border: 'none', borderRadius: 18, fontWeight: 700, fontSize: 12, cursor: 'pointer', color: '#1e3a5f' }}>← Retour</button>
          <button onClick={logout} style={{ padding: '8px 14px', background: 'linear-gradient(90deg,#ef4444,#dc2626)', color: '#fff', border: 'none', borderRadius: 18, fontWeight: 700, fontSize: 12, cursor: 'pointer' }}>Déconnexion</button>
        </div>
      </header>

      {/* ── TABS ───────────────────────────────────────────────────────────── */}
      <div style={{ padding: '18px 28px 0' }}>
        <div style={{ display: 'flex', gap: 6, background: '#f1f5f9', borderRadius: 14, padding: 5, maxWidth: 640 }}>
          {([['library','','Bibliothèque'],['sequences','','Séquences'],['aac','','AAC'],['games','','Jeux']] as const).map(([tab, icon, label]) => (
            <button key={tab} style={tabStyle(tab)} onClick={() => setActiveTab(tab)}>{icon} {label}</button>
          ))}
        </div>
      </div>

      {/* ── CONTENT ────────────────────────────────────────────────────────── */}
      <main style={{ padding: '22px 28px' }}>

        {/* ══ MODULE A — BIBLIOTHÈQUE ════════════════════════════════════════ */}
        {activeTab === 'library' && (
          <div>
            {loadingLib ? (
              <div style={{ textAlign: 'center', padding: '60px 0', color: '#64748b' }}>
                <div style={{ width: 40, height: 40, border: `4px solid #e2e8f0`, borderTopColor: catCfg.color, borderRadius: '50%', animation: 'spin .8s linear infinite', margin: '0 auto 16px' }} />
                <p style={{ fontWeight: 700 }}>Chargement…</p>
              </div>
            ) : (
              <>
                {/* Videos */}
                {videos.length > 0 && (
                  <section style={{ marginBottom: 36 }}>
                    <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800, color: '#1e3a5f', display: 'flex', gap: 8, alignItems: 'center' }}>
                       Vidéos <span style={{ fontSize: 12, background: '#f1f5f9', borderRadius: 20, padding: '2px 10px', color: '#64748b', fontWeight: 600 }}>{videos.length}</span>
                    </h2>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(210px,1fr))', gap: 16 }}>
                      {videos.map((v) => {
                        const vUrl = buildMediaUrl(v.url);
                        return (
                          <div key={v.id} style={{ background: '#fff', borderRadius: 16, overflow: 'hidden', boxShadow: '0 2px 10px rgba(0,0,0,0.07)', transition: 'transform .2s,box-shadow .2s', cursor: 'pointer' }}
                            onMouseEnter={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'translateY(-4px)'; d.style.boxShadow = '0 8px 24px rgba(0,0,0,0.12)'; }}
                            onMouseLeave={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'none'; d.style.boxShadow = '0 2px 10px rgba(0,0,0,0.07)'; }}
                          >
                            <div style={{ height: 130, background: 'linear-gradient(135deg,#e0f7fa,#b2ebf2)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 50, overflow: 'hidden' }}>
                              {vUrl ? <video src={vUrl} preload="metadata" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <span>{v.emoji || ''}</span>}
                            </div>
                            <div style={{ padding: '12px 14px 14px' }}>
                              <p style={{ margin: '0 0 6px', fontWeight: 700, fontSize: 13, color: '#1e3a5f', lineHeight: 1.3 }}>{v.title}</p>
                              <p style={{ margin: '0 0 10px', fontSize: 11, color: '#64748b' }}> {v.category} • ⏱ {v.duration}</p>
                              <button onClick={() => { const u = buildMediaUrl(v.url); if (u) window.open(u,'_blank','noopener,noreferrer'); logActivity(v.id,'video_watched'); }} style={{ width: '100%', padding: '9px 0', borderRadius: 9, border: 'none', background: 'linear-gradient(90deg,#38b2ac,#2dd4bf)', color: '#fff', fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>
                                {vUrl ? '▶ Regarder' : '⏳ Indisponible'}
                              </button>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </section>
                )}

                {/* Activities */}
                {activities.length > 0 && (
                  <section>
                    <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800, color: '#1e3a5f', display: 'flex', gap: 8, alignItems: 'center' }}>
                       Activités <span style={{ fontSize: 12, background: '#f1f5f9', borderRadius: 20, padding: '2px 10px', color: '#64748b', fontWeight: 600 }}>{activities.length}</span>
                    </h2>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                      {activities.map((a) => (
                        <div key={a.id} style={{ background: '#fff', borderRadius: 14, padding: '14px 18px', display: 'flex', alignItems: 'center', gap: 14, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', transition: 'transform .2s', cursor: 'pointer' }}
                          onMouseEnter={(e) => { (e.currentTarget as HTMLDivElement).style.transform = 'translateY(-2px)'; }}
                          onMouseLeave={(e) => { (e.currentTarget as HTMLDivElement).style.transform = 'none'; }}
                        >
                          <div style={{ width: 50, height: 50, borderRadius: 13, background: a.emojiColor || '#d1fae5', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, flexShrink: 0 }}>{a.emoji || ''}</div>
                          <div style={{ flex: 1 }}>
                            <p style={{ margin: '0 0 3px', fontWeight: 700, fontSize: 14, color: '#1e3a5f' }}>{a.title}</p>
                            <p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>{a.steps} étapes • {a.minutes} min</p>
                          </div>
                          <button onClick={() => logActivity(a.id, 'activity_started')} style={{ padding: '9px 18px', borderRadius: 9, border: 'none', background: 'linear-gradient(90deg,#38b2ac,#2dd4bf)', color: '#fff', fontWeight: 700, fontSize: 13, cursor: 'pointer', whiteSpace: 'nowrap' }}>
                            Commencer
                          </button>
                        </div>
                      ))}
                    </div>
                  </section>
                )}

                {videos.length === 0 && activities.length === 0 && (
                  <div style={{ textAlign: 'center', padding: '60px 20px' }}>
                    <div style={{ fontSize: 52, marginBottom: 14 }}></div>
                    <p style={{ fontSize: 16, fontWeight: 700, color: '#64748b' }}>Aucun contenu pour cette catégorie.</p>
                    <p style={{ fontSize: 13, color: '#94a3b8' }}>Demandez à votre accompagnateur d'ajouter du contenu.</p>
                  </div>
                )}
              </>
            )}
          </div>
        )}

        {/* ══ MODULE B — SÉQUENCES ══════════════════════════════════════════ */}
        {activeTab === 'sequences' && (
          <div>
            <h2 style={{ margin: '0 0 6px', fontSize: 18, fontWeight: 800, color: '#1e3a5f' }}> Séquences guidées</h2>
            <p style={{ margin: '0 0 20px', fontSize: 13, color: '#64748b' }}>Des activités étape par étape pour apprendre à ton rythme</p>
            {loadingSeq ? (
              <div style={{ textAlign: 'center', padding: 40, color: '#64748b' }}>⏳ Chargement…</div>
            ) : sequences.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '60px 20px' }}>
                <div style={{ fontSize: 48, marginBottom: 12 }}></div>
                <p style={{ fontWeight: 700, color: '#64748b' }}>Aucune séquence disponible</p>
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(250px,1fr))', gap: 16 }}>
                {sequences.map((seq) => {
                  const diffColor = seq.difficulty === 'facile' ? '#10b981' : seq.difficulty === 'moyen' ? '#f59e0b' : '#ef4444';
                  return (
                    <div key={seq.id} style={{ background: '#fff', borderRadius: 18, padding: '18px 20px', boxShadow: '0 2px 10px rgba(0,0,0,0.07)', transition: 'transform .2s,box-shadow .2s,border-color .2s', cursor: 'pointer', border: '2px solid transparent' }}
                      onMouseEnter={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'translateY(-4px)'; d.style.boxShadow = '0 10px 28px rgba(0,0,0,0.12)'; d.style.borderColor = catCfg.color; }}
                      onMouseLeave={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'none'; d.style.boxShadow = '0 2px 10px rgba(0,0,0,0.07)'; d.style.borderColor = 'transparent'; }}
                    >
                      <div style={{ fontSize: 38, marginBottom: 10 }}>{seq.emoji}</div>
                      <h3 style={{ margin: '0 0 5px', fontSize: 15, fontWeight: 800, color: '#1e3a5f' }}>{seq.title}</h3>
                      <p style={{ margin: '0 0 10px', fontSize: 12, color: '#64748b', lineHeight: 1.5 }}>{seq.description}</p>
                      <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
                        <span style={{ fontSize: 10, background: '#f1f5f9', borderRadius: 20, padding: '2px 8px', color: '#64748b', fontWeight: 600 }}>⏱ {seq.duration_minutes} min</span>
                        <span style={{ fontSize: 10, background: `${diffColor}18`, borderRadius: 20, padding: '2px 8px', color: diffColor, fontWeight: 700 }}>{seq.difficulty}</span>
                      </div>
                      <button onClick={() => openSequence(seq)} style={{ width: '100%', padding: '10px 0', borderRadius: 10, border: 'none', background: `linear-gradient(135deg,${catCfg.color},${catCfg.color}cc)`, color: '#fff', fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>
                        Commencer →
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {/* ══ MODULE C — AAC ════════════════════════════════════════════════ */}
        {activeTab === 'aac' && (
          <div>
            <h2 style={{ margin: '0 0 6px', fontSize: 18, fontWeight: 800, color: '#1e3a5f' }}> Communication alternative</h2>
            <p style={{ margin: '0 0 18px', fontSize: 13, color: '#64748b' }}>Clique sur les pictogrammes pour t'exprimer</p>

            {/* Phrase builder */}
            <div style={{ background: '#fff', borderRadius: 14, padding: '12px 16px', marginBottom: 14, minHeight: 62, display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap', boxShadow: '0 2px 10px rgba(0,0,0,0.06)', border: '2px dashed #e2e8f0' }}>
              {aacPhrase.length === 0 ? (
                <p style={{ color: '#94a3b8', fontSize: 13, margin: 0 }}> Clique sur un pictogramme pour construire ta phrase…</p>
              ) : (
                aacPhrase.map((s, i) => (
                  <span key={i} onClick={() => setAACPhrase((p) => p.filter((_, idx) => idx !== i))} style={{ background: `${s.color}18`, border: `2px solid ${s.color}44`, borderRadius: 10, padding: '5px 10px', fontSize: 14, fontWeight: 700, color: '#1e3a5f', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 5 }} title="Cliquer pour retirer">
                    {s.emoji} {s.label}
                  </span>
                ))
              )}
            </div>

            {aacPhrase.length > 0 && (
              <div style={{ display: 'flex', gap: 8, marginBottom: 18 }}>
                <button onClick={() => speak(aacPhrase.map((s) => s.label).join('. '))} style={{ padding: '10px 18px', borderRadius: 10, border: 'none', background: 'linear-gradient(135deg,#3b82f6,#60a5fa)', color: '#fff', fontWeight: 700, fontSize: 13, cursor: 'pointer' }}> Parler</button>
                <button onClick={() => setAACPhrase([])} style={{ padding: '10px 18px', borderRadius: 10, border: '2px solid #e2e8f0', background: '#fff', color: '#64748b', fontWeight: 700, fontSize: 13, cursor: 'pointer' }}> Effacer</button>
              </div>
            )}

            {loadingAAC ? (
              <div style={{ textAlign: 'center', padding: 40, color: '#64748b' }}>⏳ Chargement…</div>
            ) : (
              <>
                <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
                  {aacCategories.map((cat) => (
                    <button key={cat} onClick={() => setActiveAACCat(cat)} style={{ padding: '7px 16px', borderRadius: 18, border: 'none', cursor: 'pointer', fontWeight: 700, fontSize: 12, background: activeAACCat === cat ? '#1e3a5f' : '#f1f5f9', color: activeAACCat === cat ? '#fff' : '#64748b', transition: 'all .2s' }}>
                      {cat}
                    </button>
                  ))}
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(100px,1fr))', gap: 10 }}>
                  {aacSymbols.filter((s) => s.category === activeAACCat).map((sym) => (
                    <button key={sym.id} onClick={() => { setAACPhrase((p) => [...p, sym]); speak(sym.label); }} style={{ background: '#fff', border: `2px solid ${sym.color}44`, borderRadius: 14, padding: '12px 8px', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, boxShadow: '0 2px 6px rgba(0,0,0,0.06)', transition: 'transform .15s,border-color .15s,box-shadow .15s' }}
                      onMouseEnter={(e) => { const b = e.currentTarget as HTMLButtonElement; b.style.transform = 'scale(1.06)'; b.style.borderColor = sym.color; b.style.boxShadow = `0 6px 18px ${sym.color}33`; }}
                      onMouseLeave={(e) => { const b = e.currentTarget as HTMLButtonElement; b.style.transform = 'scale(1)'; b.style.borderColor = `${sym.color}44`; b.style.boxShadow = '0 2px 6px rgba(0,0,0,0.06)'; }}
                    >
                      <span style={{ fontSize: 30 }}>{sym.emoji}</span>
                      <span style={{ fontSize: 10, fontWeight: 700, color: '#1e3a5f', textAlign: 'center', lineHeight: 1.3 }}>{sym.label}</span>
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        )}

        {/* ══ MODULE D — JEUX ══════════════════════════════════════════════ */}
        {activeTab === 'games' && (
          <div>
            <h2 style={{ margin: '0 0 6px', fontSize: 18, fontWeight: 800, color: '#1e3a5f' }}> Mini-jeux</h2>
            <p style={{ margin: '0 0 20px', fontSize: 13, color: '#64748b' }}>Joue et gagne des points !</p>

            {/* Stats banner */}
            <div style={{ background: 'linear-gradient(135deg,#1e3a5f,#2d5a8e)', borderRadius: 18, padding: '18px 24px', marginBottom: 24, display: 'flex', gap: 20, alignItems: 'center', flexWrap: 'wrap' }}>
              <div style={{ color: '#fff' }}>
                <div style={{ fontSize: 11, opacity: 0.7, fontWeight: 600, marginBottom: 3 }}>POINTS TOTAUX</div>
                <div style={{ fontSize: 28, fontWeight: 900 }}>⭐ {stats.total_points}</div>
              </div>
              <div style={{ color: '#fff' }}>
                <div style={{ fontSize: 11, opacity: 0.7, fontWeight: 600, marginBottom: 3 }}>ACTIVITÉS</div>
                <div style={{ fontSize: 28, fontWeight: 900 }}> {stats.total_activities}</div>
              </div>
              <div style={{ color: '#fff' }}>
                <div style={{ fontSize: 11, opacity: 0.7, fontWeight: 600, marginBottom: 3 }}>BADGES</div>
                <div style={{ fontSize: 28, fontWeight: 900 }}> {badges.length}</div>
              </div>
            </div>

            {/* Game cards */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(250px,1fr))', gap: 18, marginBottom: 28 }}>
              {[
                { key: 'memory' as const, emoji: '', title: 'Jeu de mémoire', desc: 'Retourne les cartes et trouve les paires. Entraîne ta mémoire !', bg: 'linear-gradient(135deg,#d1fae5,#a7f3d0)', btnBg: 'linear-gradient(135deg,#10b981,#34d399)', borderHover: '#10b981', tags: [' 16 cartes', '⭐ Jusqu\'à 100 pts'] },
                { key: 'color'  as const, emoji: '', title: 'Jeu des couleurs', desc: 'Lis le mot et clique sur la bonne couleur. Réfléchis vite !', bg: 'linear-gradient(135deg,#fef3c7,#fde68a)', btnBg: 'linear-gradient(135deg,#f59e0b,#fcd34d)', borderHover: '#f59e0b', tags: [' 10 tours', '⭐ Jusqu\'à 100 pts'] },
              ].map(({ key, emoji, title, desc, bg, btnBg, borderHover, tags }) => (
                <div key={key} style={{ background: '#fff', borderRadius: 18, overflow: 'hidden', boxShadow: '0 2px 14px rgba(0,0,0,0.07)', border: '2px solid transparent', transition: 'all .25s' }}
                  onMouseEnter={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'translateY(-4px)'; d.style.borderColor = borderHover; d.style.boxShadow = `0 10px 28px ${borderHover}33`; }}
                  onMouseLeave={(e) => { const d = e.currentTarget as HTMLDivElement; d.style.transform = 'none'; d.style.borderColor = 'transparent'; d.style.boxShadow = '0 2px 14px rgba(0,0,0,0.07)'; }}
                >
                  <div style={{ height: 110, background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 50 }}>{emoji}</div>
                  <div style={{ padding: '16px 18px 18px' }}>
                    <h3 style={{ margin: '0 0 6px', fontSize: 16, fontWeight: 800, color: '#1e3a5f' }}>{title}</h3>
                    <p style={{ margin: '0 0 12px', fontSize: 12, color: '#64748b', lineHeight: 1.5 }}>{desc}</p>
                    <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
                      {tags.map((t) => <span key={t} style={{ fontSize: 10, background: '#f1f5f9', borderRadius: 20, padding: '2px 8px', color: '#64748b', fontWeight: 700 }}>{t}</span>)}
                    </div>
                    <button onClick={() => setActiveGame(key)} style={{ width: '100%', padding: '11px 0', borderRadius: 10, border: 'none', background: btnBg, color: '#fff', fontWeight: 800, fontSize: 14, cursor: 'pointer', boxShadow: `0 4px 14px ${borderHover}44` }}>
                       Jouer !
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {/* Badges */}
            {badges.length > 0 && (
              <div>
                <h3 style={{ margin: '0 0 12px', fontSize: 15, fontWeight: 800, color: '#1e3a5f' }}> Mes badges</h3>
                <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                  {badges.map((b) => (
                    <div key={b.id} style={{ background: `${b.color}18`, border: `2px solid ${b.color}44`, borderRadius: 12, padding: '8px 14px', display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{ fontSize: 20 }}>{b.emoji}</span>
                      <span style={{ fontSize: 12, fontWeight: 700, color: '#1e3a5f' }}>{b.name}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* ── GAME MODALS ──────────────────────────────────────────────────────── */}
      {activeGame === 'memory' && (
        <MemoryGame
          onComplete={(score, dur) => { logGameScore('memory', score, dur); setTimeout(() => setActiveGame(null), 2000); }}
          onClose={() => setActiveGame(null)}
        />
      )}
      {activeGame === 'color' && (
        <ColorMatchGame
          onComplete={(score, dur) => { logGameScore('color_match', score, dur); setTimeout(() => setActiveGame(null), 2000); }}
          onClose={() => setActiveGame(null)}
        />
      )}

      {/* ── SEQUENCE MODAL ───────────────────────────────────────────────────── */}
      {activeSequence && (
        <SequenceViewer
          sequence={activeSequence}
          onClose={() => setActiveSequence(null)}
          onComplete={(score, dur) => { logGameScore(`seq_${activeSequence.id}`, score, dur); setTimeout(() => setActiveSequence(null), 1800); }}
        />
      )}

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

// ============================================================================
// CHILD SELECTION PAGE — Pharmacy Green Design
// ============================================================================

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../features/auth/hooks/useAuth';
import api from '../lib/api';
import '../styles/ChildSelectionPage.css';

interface Child {
  id: number;
  name: string;
  age: number;
}

interface ApiResult<T> {
  success: boolean;
  data: T;
  message?: string;
}

const CROSS_COUNT = 30; // 6 cols × 5 rows

export const ChildSelectionPage = (): JSX.Element => {
  const navigate = useNavigate();
  const { logout } = useAuth();
  const [children, setChildren] = useState<Child[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedChildId, setSelectedChildId] = useState<number | null>(null);

  // Fetch children on mount
  useEffect(() => {
    const fetchChildren = async () => {
      try {
        setLoading(true);
        const { data } = await api.get<ApiResult<Child[]>>('/api/child/mychildren');
        if (data.success && data.data.length > 0) {
          setChildren(data.data);
        }
      } catch (err) {
        console.error('Error fetching children:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchChildren();
  }, []);

  const handleSelectChild = (childId: number) => {
    setSelectedChildId(childId);
    // Store selected child in localStorage for the dashboard to use
    localStorage.setItem('selected_child_id', childId.toString());
    // Navigate to child mode dashboard
    setTimeout(() => navigate('/child'), 300);
  };

  const handleLogout = () => {
    localStorage.removeItem('selected_child_id');
    logout();
  };

  return (
    <div className="cs-page">
      {/* Decorative cross pattern */}
      <div className="cs-pattern" aria-hidden="true">
        {Array.from({ length: CROSS_COUNT }).map((_, i) => (
          <div key={i} className="cs-cross" />
        ))}
      </div>

      {/* Top bar: Back + Logout */}
      <div className="cs-topbar">
        <button type="button" className="cs-back-btn" onClick={() => navigate('/role-selection')}>
          ← Retour
        </button>
        <button type="button" className="cs-logout-btn" onClick={handleLogout}>
          ⎋ Déconnexion
        </button>
      </div>

      {/* Brand header */}
      <div className="cs-brand">
        <div className="cs-logo"></div>
        <h1 className="cs-title">AIDAA</h1>
        <p className="cs-subtitle">Sélectionnez un enfant pour continuer</p>
      </div>

      {/* Content */}
      {loading ? (
        <div className="cs-state">
          <div className="cs-spinner" />
          <p className="cs-state__title">Chargement…</p>
          <p className="cs-state__desc">Récupération de la liste des enfants</p>
        </div>
      ) : children.length > 0 ? (
        <>
          <p className="cs-instruction">Quel enfant souhaitez-vous gérer aujourd'hui ?</p>
          <div className="cs-grid">
            {children.map((child) => (
              <div
                key={child.id}
                className={`cs-card${selectedChildId === child.id ? ' cs-card--selected' : ''}`}
                onClick={() => handleSelectChild(child.id)}
              >
                <div className="cs-avatar"></div>
                <h2 className="cs-child-name">{child.name}</h2>
                <span className="cs-child-age"> {child.age} ans</span>
                <button
                  className="cs-select-btn"
                  onClick={(e) => { e.stopPropagation(); handleSelectChild(child.id); }}
                >
                  Sélectionner →
                </button>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div className="cs-state">
          <span className="cs-state__icon"></span>
          <p className="cs-state__title">Aucun enfant trouvé</p>
          <p className="cs-state__desc">
            Vous n'avez aucun enfant enregistré pour le moment.<br />
            Veuillez contacter un administrateur.
          </p>
        </div>
      )}
    </div>
  );
};

export default ChildSelectionPage;

// ============================================================================
// CHILD SELECTION PAGE — Pharmacy Green Design
// ============================================================================

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../features/auth/hooks/useAuth';
import api from '../lib/api';
import '../styles/ChildSelectionPage.css';

interface Child {
  id: number;
  name: string;
  age: number;
  participant_category: 'enfant' | 'jeune' | 'adulte';
}

interface ApiResult<T> {
  success: boolean;
  data: T;
  message?: string;
}

const CROSS_COUNT = 30; // 6 cols × 5 rows

export const ChildSelectionPage = (): JSX.Element => {
  const navigate = useNavigate();
  const { logout } = useAuth();
  const [children, setChildren] = useState<Child[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedChildId, setSelectedChildId] = useState<number | null>(null);

  // Fetch children on mount
  useEffect(() => {
    const fetchChildren = async () => {
      try {
        setLoading(true);
        const { data } = await api.get<ApiResult<Child[]>>('/api/child/mychildren');
        if (data.success && data.data.length > 0) {
          setChildren(data.data);
        }
      } catch (err) {
        console.error('Error fetching children:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchChildren();
  }, []);

  const handleSelectChild = (child: Child) => {
    setSelectedChildId(child.id);
    // Store both child ID and participant_category for ChildDashboard
    localStorage.setItem('selected_child_id', child.id.toString());
    localStorage.setItem('selected_child_name', child.name);
    localStorage.setItem('selected_child_category', child.participant_category || 'enfant');
    // Navigate to child mode dashboard
    setTimeout(() => navigate('/child'), 300);
  };

  const handleLogout = () => {
    localStorage.removeItem('selected_child_id');
    localStorage.removeItem('selected_child_name');
    localStorage.removeItem('selected_child_category');
    logout();
  };

  return (
    <div className="cs-page">
      {/* Decorative cross pattern */}
      <div className="cs-pattern" aria-hidden="true">
        {Array.from({ length: CROSS_COUNT }).map((_, i) => (
          <div key={i} className="cs-cross" />
        ))}
      </div>

      {/* Top bar: Back + Logout */}
      <div className="cs-topbar">
        <button type="button" className="cs-back-btn" onClick={() => navigate('/role-selection')}>
          ← Retour
        </button>
        <button type="button" className="cs-logout-btn" onClick={handleLogout}>
          ⎋ Déconnexion
        </button>
      </div>

      {/* Brand header */}
      <div className="cs-brand">
        <div className="cs-logo"></div>
        <h1 className="cs-title">AIDAA</h1>
        <p className="cs-subtitle">Sélectionnez un enfant pour continuer</p>
      </div>

      {/* Content */}
      {loading ? (
        <div className="cs-state">
          <div className="cs-spinner" />
          <p className="cs-state__title">Chargement…</p>
          <p className="cs-state__desc">Récupération de la liste des enfants</p>
        </div>
      ) : children.length > 0 ? (
        <>
          <p className="cs-instruction">Quel participant souhaitez-vous accompagner aujourd'hui ?</p>
          <div className="cs-grid">
            {children.map((child) => {
              const catEmoji = child.participant_category === 'adulte' ? '' : child.participant_category === 'jeune' ? '' : '';
              const catLabel = child.participant_category === 'adulte' ? 'Adulte' : child.participant_category === 'jeune' ? 'Jeune' : 'Enfant';
              return (
                <div
                  key={child.id}
                  className={`cs-card${selectedChildId === child.id ? ' cs-card--selected' : ''}`}
                  onClick={() => handleSelectChild(child)}
                >
                  <div className="cs-avatar">{catEmoji}</div>
                  <h2 className="cs-child-name">{child.name}</h2>
                  <span className="cs-child-age"> {child.age} ans</span>
                  <span className="cs-child-age" style={{ marginLeft: 6 }}>️ {catLabel}</span>
                  <button
                    className="cs-select-btn"
                    style={{ marginTop: 16 }}
                    onClick={(e) => { e.stopPropagation(); handleSelectChild(child); }}
                  >
                    Commencer →
                  </button>
                </div>
              );
            })}
          </div>
        </>
      ) : (
        <div className="cs-state">
          <span className="cs-state__icon"></span>
          <p className="cs-state__title">Aucun enfant trouvé</p>
          <p className="cs-state__desc">
            Vous n'avez aucun enfant enregistré pour le moment.<br />
            Veuillez contacter un administrateur.
          </p>
        </div>
      )}
    </div>
  );
};

export default ChildSelectionPage;

/* ============================================================================
   PARENT DASHBOARD — Admin-style Fixed Sidebar Layout
   Same pattern as AdminPanel.css
   ============================================================================ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

/* ── Palette ── */
:root {
  --pd-green:       #00A651;
  --pd-green-dark:  #007A3A;
  --pd-green-deep:  #00572A;
  --pd-green-light: #E6F7EE;
  --pd-green-mid:   #C2EAD4;
  --pd-sidebar-bg:  #013D1C;
  --pd-sidebar-w:   280px;
  --pd-white:       #FFFFFF;
  --pd-off-white:   #F4FAF7;
  --pd-text-dark:   #0F2318;
  --pd-text-light:  #7A9485;
  --pd-border:      #D1E8DB;
  --pd-shadow:      0 4px 24px rgba(0,122,58,.12);
}

/* ── Root layout (flex, same as adm-layout) ── */
.pd-layout {
  display: flex;
  min-height: 100vh;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: linear-gradient(160deg, var(--pd-green-deep) 0%, var(--pd-green-dark) 50%, var(--pd-green) 100%);
}

/* ═══════════════════════════════════════════════
   SIDEBAR — fixed full-height (like adm-sidebar)
═══════════════════════════════════════════════ */
.pd-sidebar {
  width: var(--pd-sidebar-w);
  background: var(--pd-sidebar-bg);
  display: flex;
  flex-direction: column;
  position: fixed;
  top: 0; left: 0; bottom: 0;
  z-index: 100;
  overflow-y: auto;
  overflow-x: hidden;
}

/* Scrollbar */
.pd-sidebar::-webkit-scrollbar { width: 4px; }
.pd-sidebar::-webkit-scrollbar-track { background: transparent; }
.pd-sidebar::-webkit-scrollbar-thumb { background: rgba(255,255,255,.12); border-radius: 2px; }

/* Brand */
.pd-sidebar__brand {
  padding: 22px 18px 18px;
  border-bottom: 1px solid rgba(255,255,255,.07);
  display: flex;
  align-items: center;
  gap: 11px;
  flex-shrink: 0;
}

.pd-sidebar__logo {
  width: 38px; height: 38px;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
}

.pd-sidebar__brand-text h2 {
  color: #fff;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: -.3px;
  margin: 0;
}
.pd-sidebar__brand-text span {
  color: rgba(255,255,255,.38);
  font-size: 10.5px;
  letter-spacing: .7px;
  text-transform: uppercase;
}

/* Nav */
.pd-sidebar__nav {
  padding: 14px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex-shrink: 0;
}

.pd-nav__label {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 10px 8px 5px;
}

.pd-nav__item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 13px;
  border-radius: 10px;
  cursor: pointer;
  border: none;
  background: transparent;
  color: rgba(255,255,255,.52);
  font-size: 13.5px;
  font-weight: 500;
  font-family: inherit;
  text-align: left;
  width: 100%;
  transition: all .18s;
  white-space: nowrap;
}
.pd-nav__item .nav-icon { font-size: 16px; flex-shrink: 0; }
.pd-nav__item:hover { background: rgba(255,255,255,.06); color: rgba(255,255,255,.9); }
.pd-nav__item.active {
  background: linear-gradient(90deg, rgba(0,166,81,.3), rgba(0,166,81,.12));
  color: #fff;
  border-left: 3px solid var(--pd-green);
  font-weight: 600;
}

/* Children section */
.pd-sidebar__children {
  padding: 0 10px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  margin-top: 4px;
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}
.pd-sidebar__children::-webkit-scrollbar { width: 3px; }
.pd-sidebar__children::-webkit-scrollbar-thumb { background: rgba(255,255,255,.1); border-radius: 2px; }

.pd-section-title {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 12px 8px 6px;
}

/* Child item */
.pd-child-item {
  border-radius: 8px;
  background: rgba(255,255,255,.06);
  margin-bottom: 5px;
  overflow: hidden;
  border: 1px solid transparent;
  transition: border-color .2s;
}
.pd-child-item.active { background: rgba(255,255,255,.13); border-color: rgba(255,255,255,.18); }

.pd-child-main {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  border: 0;
  background: transparent;
  color: rgba(255,255,255,.85);
  padding: 7px 8px;
  cursor: pointer;
  text-align: left;
  font-size: 12.5px;
  font-family: inherit;
  font-weight: 500;
}

.pd-child-avatar {
  width: 24px; height: 24px;
  border-radius: 50%;
  background: var(--pd-green-mid);
  color: var(--pd-green-deep);
  display: flex; align-items: center; justify-content: center;
  font-size: 10px; font-weight: 800;
  flex-shrink: 0;
}

.pd-child-row-actions {
  display: flex;
  gap: 3px;
  padding: 0 7px 6px;
}

.pd-child-action-btn {
  flex: 1;
  border: 1px solid rgba(255,255,255,.18);
  border-radius: 6px;
  background: rgba(255,255,255,.08);
  color: rgba(255,255,255,.7);
  padding: 3px 6px;
  cursor: pointer;
  font-size: 11px;
  transition: background .18s;
  font-family: inherit;
}
.pd-child-action-btn:hover { background: rgba(255,255,255,.18); color: #fff; }
.pd-child-action-btn--danger { background: rgba(220,38,38,.2); border-color: rgba(248,113,113,.4); }

/* Edit form */
.pd-child-edit-form {
  padding: 0 7px 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.pd-child-edit-form input,
.pd-child-edit-form select {
  width: 100%;
  border: 1px solid rgba(255,255,255,.25);
  border-radius: 6px;
  background: rgba(255,255,255,.1);
  color: #fff;
  padding: 6px 8px;
  font-size: 12px;
  font-family: inherit;
}
.pd-child-edit-form select option { color: #0f2318; }
.pd-child-edit-actions { display: flex; gap: 5px; }
.pd-child-edit-actions button {
  flex: 1;
  border: 0;
  border-radius: 6px;
  padding: 6px 8px;
  cursor: pointer;
  font-size: 11.5px;
  font-family: inherit;
  font-weight: 600;
}
.pd-child-edit-actions button:first-child { background: var(--pd-green); color: #fff; }
.pd-child-edit-actions button:last-child { background: rgba(255,255,255,.12); color: rgba(255,255,255,.75); }

/* Create form */
.pd-create-form {
  padding: 10px 8px 4px;
  border-top: 1px solid rgba(255,255,255,.07);
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.pd-create-form h5 {
  margin: 0 0 2px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: .7px;
  color: rgba(255,255,255,.38);
  text-transform: uppercase;
}
.pd-create-form input,
.pd-create-form select {
  width: 100%;
  border: 1px solid rgba(255,255,255,.22);
  border-radius: 7px;
  background: rgba(255,255,255,.1);
  color: #fff;
  padding: 8px 10px;
  font-size: 12.5px;
  font-family: inherit;
}
.pd-create-form input::placeholder { color: rgba(255,255,255,.42); }
.pd-create-form select option { color: #0f2318; }
.pd-create-form button {
  border: 0;
  border-radius: 8px;
  background: #fff;
  color: var(--pd-green-dark);
  padding: 9px 12px;
  font-weight: 700;
  font-size: 12.5px;
  cursor: pointer;
  font-family: inherit;
  transition: background .18s, transform .15s;
  box-shadow: 0 2px 8px rgba(0,0,0,.1);
}
.pd-create-form button:hover:not(:disabled) { background: var(--pd-green-light); transform: translateY(-1px); }
.pd-create-form button:disabled { opacity: .6; cursor: not-allowed; }

/* Sidebar footer */
.pd-sidebar__footer {
  padding: 12px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  flex-shrink: 0;
}
.pd-logout-btn {
  width: 100%;
  padding: 10px 13px;
  border-radius: 10px;
  border: 1px solid rgba(239,68,68,.28);
  background: rgba(239,68,68,.07);
  color: #fca5a5;
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all .18s;
}
.pd-logout-btn:hover { background: rgba(239,68,68,.18); color: #fecaca; }

/* ═══════════════════════════════════════════════
   MAIN — offset by sidebar width (like adm-main)
═══════════════════════════════════════════════ */
.pd-main {
  margin-left: var(--pd-sidebar-w);
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* ── Topbar (sticky, like adm-topbar) ── */
.pd-topbar {
  background: rgba(255,255,255,.92);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--pd-border);
  padding: 0 28px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 50;
  flex-shrink: 0;
  gap: 16px;
}

.pd-topbar__left { flex: 1; min-width: 0; }
.pd-topbar__breadcrumb { font-size: 11.5px; color: var(--pd-text-light); font-weight: 500; margin-bottom: 2px; }
.pd-topbar__title { font-size: 19px; font-weight: 800; color: var(--pd-text-dark); margin: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.pd-topbar__right { display: flex; align-items: center; gap: 12px; flex-shrink: 0; }

.pd-child-select {
  display: flex;
  align-items: center;
  gap: 8px;
}
.pd-child-select label {
  font-size: 13px;
  font-weight: 600;
  color: var(--pd-text-light);
  white-space: nowrap;
}
.pd-child-select select {
  padding: 8px 12px;
  border-radius: 9px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-text-dark);
  font-size: 13px;
  font-family: inherit;
  font-weight: 500;
  cursor: pointer;
  min-width: 170px;
}

/* ── Content area ── */
.pd-content {
  flex: 1;
  padding: 26px 30px;
  overflow-y: auto;
}

/* ── Hero banner ── */
.pd-hero {
  background: rgba(255,255,255,.13);
  border: 1px solid rgba(255,255,255,.18);
  backdrop-filter: blur(6px);
  border-radius: 16px;
  padding: 18px 22px;
  color: #fff;
  margin-bottom: 22px;
}
.pd-hero h2 { margin: 0; font-size: 20px; font-weight: 800; }
.pd-hero p { margin: 6px 0 0; color: rgba(255,255,255,.72); font-size: 13.5px; }

/* ── Section title ── */
.pd-section-h2 {
  font-size: 17px;
  font-weight: 800;
  color: #fff;
  margin: 0 0 18px;
}

/* ── Stat cards ── */
.pd-stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
  gap: 14px;
  margin-bottom: 20px;
}
.pd-stat-card {
  background: var(--pd-white);
  border-radius: 14px;
  padding: 20px;
  text-align: center;
  border: 1.5px solid var(--pd-border);
  box-shadow: var(--pd-shadow);
  transition: transform .2s, box-shadow .2s;
}
.pd-stat-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(0,166,81,.15); }
.pd-stat-icon { font-size: 30px; margin-bottom: 8px; }
.pd-stat-label { color: var(--pd-text-light); font-size: 12.5px; font-weight: 500; margin-bottom: 4px; }
.pd-stat-value { font-size: 30px; font-weight: 800; color: var(--pd-green-dark); }

/* ── White panel ── */
.pd-panel {
  background: var(--pd-white);
  border-radius: 16px;
  padding: 20px;
  border: 1.5px solid var(--pd-border);
  box-shadow: var(--pd-shadow);
}
.pd-panel h3 { margin: 0 0 12px; color: var(--pd-text-dark); font-weight: 700; font-size: 15px; }

/* ── Empty inline ── */
.pd-empty-inline {
  padding: 14px;
  background: var(--pd-green-light);
  border: 1px dashed var(--pd-green-mid);
  border-radius: 10px;
  color: var(--pd-text-light);
  font-size: 13.5px;
}

/* ── KPI grid ── */
.pd-kpi-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
  margin-bottom: 20px;
}
.pd-kpi {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 14px;
  padding: 16px;
  box-shadow: var(--pd-shadow);
  transition: transform .2s;
}
.pd-kpi:hover { transform: translateY(-3px); }
.pd-kpi-icon {
  width: 34px; height: 34px;
  border-radius: 9px;
  background: var(--pd-green-light);
  display: flex; align-items: center; justify-content: center;
  font-size: 16px;
  margin-bottom: 10px;
}
.pd-kpi-val { font-size: 22px; font-weight: 800; color: var(--pd-text-dark); }
.pd-kpi-label { font-size: 12px; color: var(--pd-text-light); font-weight: 500; margin-top: 2px; }
.pd-kpi-change { font-size: 11px; margin-top: 6px; font-weight: 600; color: var(--pd-green-dark); }

/* ── Charts ── */
.pd-charts-row { display: grid; grid-template-columns: 1.4fr 1fr; gap: 14px; margin-bottom: 20px; }
.pd-chart-card {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 14px;
  padding: 18px;
  box-shadow: var(--pd-shadow);
}
.pd-chart-card h3 { font-size: 13px; color: var(--pd-text-dark); margin: 0 0 12px; font-weight: 700; }
.pd-chart-wrap { position: relative; }

/* ── Progress bars ── */
.pd-progress-list { display: flex; flex-direction: column; gap: 10px; }
.pd-prog-row { display: flex; align-items: center; gap: 10px; }
.pd-prog-label { font-size: 12px; color: var(--pd-text-dark); width: 160px; font-weight: 500; flex-shrink: 0; }
.pd-prog-bar-bg { flex: 1; height: 8px; background: var(--pd-green-light); border-radius: 999px; }
.pd-prog-bar { height: 100%; border-radius: inherit; transition: width .6s ease; }
.pd-prog-val { font-size: 12px; color: var(--pd-text-light); width: 36px; text-align: right; font-weight: 600; }

/* ── Notes ── */
.pd-notes-list { display: flex; flex-direction: column; gap: 12px; }
.pd-note-card {
  background: var(--pd-off-white);
  padding: 16px;
  border-radius: 12px;
  border: 1.5px solid var(--pd-border);
  border-left: 4px solid var(--pd-green);
}
.pd-note-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
.pd-note-header h3 { margin: 0; color: var(--pd-text-dark); font-size: 14px; font-weight: 700; }
.pd-note-header small { color: var(--pd-text-light); font-size: 12px; }
.pd-note-content { color: #4B7A62; font-size: 13.5px; line-height: 1.6; margin: 0; }

/* ── Coming soon ── */
.pd-coming-soon {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 16px;
  text-align: center;
  padding: 50px 30px;
  box-shadow: var(--pd-shadow);
}
.pd-coming-soon h2 { color: var(--pd-text-dark); font-weight: 800; margin-bottom: 12px; font-size: 20px; }
.pd-coming-soon p { color: var(--pd-text-light); font-size: 14px; }

/* ── Empty state (no children) ── */
.pd-empty-state {
  background: rgba(255,255,255,.13);
  border: 1px dashed rgba(255,255,255,.3);
  border-radius: 16px;
  padding: 40px 28px;
  text-align: center;
  color: rgba(255,255,255,.85);
  font-size: 14px;
  line-height: 1.6;
}

/* ── Invite professional ── */
.pd-invite-input {
  width: 100%;
  padding: 10px 13px;
  border: 1.5px solid var(--pd-border);
  border-radius: 10px;
  font-size: 14px;
  font-family: inherit;
  background: var(--pd-off-white);
  color: var(--pd-text-dark);
  transition: border-color .18s, box-shadow .18s;
}

.pd-invite-input:focus {
  outline: none;
  border-color: var(--pd-green);
  background: #fff;
  box-shadow: 0 0 0 4px rgba(0,166,81,.12);
}

.pd-invite-error {
  font-size: 13px;
  color: #b91c1c;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 9px;
  padding: 10px 14px;
  font-weight: 500;
}

.pd-invite-btn {
  padding: 11px 22px;
  border-radius: 10px;
  border: none;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  color: #fff;
  font-size: 14px;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  box-shadow: 0 4px 14px rgba(0,166,81,.35);
  transition: all .18s;
}

.pd-invite-btn:hover:not(:disabled) { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(0,166,81,.5); }
.pd-invite-btn:disabled { opacity: .55; cursor: not-allowed; transform: none; }

.pd-invite-success {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-green-mid);
  border-left: 4px solid var(--pd-green);
  border-radius: 14px;
  padding: 22px;
  display: flex;
  gap: 16px;
  box-shadow: var(--pd-shadow);
}

.pd-invite-success__icon { font-size: 28px; flex-shrink: 0; }

.pd-invite-success__body { flex: 1; }

.pd-invite-success__body h4 {
  margin: 0 0 8px;
  font-size: 15px;
  font-weight: 700;
  color: var(--pd-text-dark);
}

.pd-invite-success__body p {
  font-size: 13.5px;
  color: var(--pd-text-light);
  line-height: 1.6;
  margin: 0 0 14px;
}

.pd-invite-link-box {
  background: var(--pd-green-light);
  border: 1px solid var(--pd-green-mid);
  border-radius: 9px;
  padding: 12px 14px;
}

.pd-invite-new-btn {
  margin-top: 14px;
  padding: 8px 16px;
  border-radius: 9px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-green-dark);
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background .18s;
}

.pd-invite-new-btn:hover { background: var(--pd-green-light); border-color: var(--pd-green-mid); }

/* ── Professional list ── */
.pd-prof-list { display: flex; flex-direction: column; gap: 10px; }

.pd-prof-item {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 16px;
  background: var(--pd-off-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 12px;
  transition: box-shadow .2s;
}
.pd-prof-item:hover { box-shadow: 0 3px 14px rgba(0,122,58,.1); }

.pd-prof-avatar {
  width: 42px; height: 42px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  color: #fff;
  font-size: 16px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.pd-prof-info { flex: 1; overflow: hidden; }
.pd-prof-info strong { display: block; font-size: 14px; font-weight: 700; color: var(--pd-text-dark); }
.pd-prof-info span  { display: block; font-size: 12.5px; color: var(--pd-text-light); margin-top: 1px; }
.pd-prof-info small { display: block; font-size: 11px; color: #aabfb5; margin-top: 2px; }

.pd-prof-badge {
  font-size: 12px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: 20px;
  flex-shrink: 0;
}
.pd-prof-badge--active  { background: #dcfce7; color: #166534; }
.pd-prof-badge--pending { background: #fef9c3; color: #854d0e; }
.pd-prof-badge--revoked { background: #fee2e2; color: #991b1b; }

.pd-prof-actions { display: flex; gap: 6px; flex-shrink: 0; }

.pd-prof-btn {
  padding: 7px 13px;
  border-radius: 8px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-green-dark);
  font-size: 12px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: all .18s;
  white-space: nowrap;
}
.pd-prof-btn:hover:not(:disabled) { background: var(--pd-green-light); border-color: var(--pd-green-mid); }
.pd-prof-btn--danger { background: #fef2f2; color: #b91c1c; border-color: #fecaca; }
.pd-prof-btn--danger:hover:not(:disabled) { background: #fee2e2; }
.pd-prof-btn:disabled { opacity: .55; cursor: not-allowed; }

/* ── Inline action message ── */
.pd-action-msg {
  padding: 12px 16px;
  border-radius: 10px;
  font-size: 13.5px;
  font-weight: 500;
  margin-bottom: 16px;
}
.pd-action-msg--success { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
.pd-action-msg--error   { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }

/* ── Responsive ── */
@media (max-width: 900px) {
  .pd-layout { flex-direction: column; }
  .pd-sidebar {
    position: relative;
    width: 100%;
    top: auto; left: auto; bottom: auto;
  }
  .pd-main { margin-left: 0; }
  .pd-topbar { height: auto; padding: 14px 18px; flex-direction: column; align-items: flex-start; gap: 10px; }
  .pd-topbar__right { width: 100%; }
  .pd-child-select { width: 100%; }
  .pd-child-select select { flex: 1; }
  .pd-content { padding: 16px 18px; }
  .pd-kpi-grid { grid-template-columns: repeat(2, 1fr); }
  .pd-charts-row { grid-template-columns: 1fr; }
}

@media (max-width: 600px) {
  .pd-kpi-grid { grid-template-columns: 1fr; }
  .pd-stats-grid { grid-template-columns: 1fr; }
}

/* ============================================================================
   PARENT DASHBOARD — Admin-style Fixed Sidebar Layout
   Same pattern as AdminPanel.css
   ============================================================================ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

/* ── Palette ── */
:root {
  --pd-green:       #00A651;
  --pd-green-dark:  #007A3A;
  --pd-green-deep:  #00572A;
  --pd-green-light: #E6F7EE;
  --pd-green-mid:   #C2EAD4;
  --pd-sidebar-bg:  #013D1C;
  --pd-sidebar-w:   280px;
  --pd-white:       #FFFFFF;
  --pd-off-white:   #F4FAF7;
  --pd-text-dark:   #0F2318;
  --pd-text-light:  #7A9485;
  --pd-border:      #D1E8DB;
  --pd-shadow:      0 4px 24px rgba(0,122,58,.12);
}

/* ── Root layout (flex, same as adm-layout) ── */
.pd-layout {
  display: flex;
  min-height: 100vh;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: linear-gradient(160deg, var(--pd-green-deep) 0%, var(--pd-green-dark) 50%, var(--pd-green) 100%);
}

/* ═══════════════════════════════════════════════
   SIDEBAR — fixed full-height (like adm-sidebar)
═══════════════════════════════════════════════ */
.pd-sidebar {
  width: var(--pd-sidebar-w);
  background: var(--pd-sidebar-bg);
  display: flex;
  flex-direction: column;
  position: fixed;
  top: 0; left: 0; bottom: 0;
  z-index: 100;
  overflow-y: auto;
  overflow-x: hidden;
}

/* Scrollbar */
.pd-sidebar::-webkit-scrollbar { width: 4px; }
.pd-sidebar::-webkit-scrollbar-track { background: transparent; }
.pd-sidebar::-webkit-scrollbar-thumb { background: rgba(255,255,255,.12); border-radius: 2px; }

/* Brand */
.pd-sidebar__brand {
  padding: 22px 18px 18px;
  border-bottom: 1px solid rgba(255,255,255,.07);
  display: flex;
  align-items: center;
  gap: 11px;
  flex-shrink: 0;
}

.pd-sidebar__logo {
  width: 38px; height: 38px;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
}

.pd-sidebar__brand-text h2 {
  color: #fff;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: -.3px;
  margin: 0;
}
.pd-sidebar__brand-text span {
  color: rgba(255,255,255,.38);
  font-size: 10.5px;
  letter-spacing: .7px;
  text-transform: uppercase;
}

/* Nav */
.pd-sidebar__nav {
  padding: 14px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex-shrink: 0;
}

.pd-nav__label {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 10px 8px 5px;
}

.pd-nav__item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 13px;
  border-radius: 10px;
  cursor: pointer;
  border: none;
  background: transparent;
  color: rgba(255,255,255,.52);
  font-size: 13.5px;
  font-weight: 500;
  font-family: inherit;
  text-align: left;
  width: 100%;
  transition: all .18s;
  white-space: nowrap;
}
.pd-nav__item .nav-icon { font-size: 16px; flex-shrink: 0; }
.pd-nav__item:hover { background: rgba(255,255,255,.06); color: rgba(255,255,255,.9); }
.pd-nav__item.active {
  background: linear-gradient(90deg, rgba(0,166,81,.3), rgba(0,166,81,.12));
  color: #fff;
  border-left: 3px solid var(--pd-green);
  font-weight: 600;
}

/* Children section */
.pd-sidebar__children {
  padding: 0 10px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  margin-top: 4px;
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}
.pd-sidebar__children::-webkit-scrollbar { width: 3px; }
.pd-sidebar__children::-webkit-scrollbar-thumb { background: rgba(255,255,255,.1); border-radius: 2px; }

.pd-section-title {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 12px 8px 6px;
}

/* Child item */
.pd-child-item {
  border-radius: 8px;
  background: rgba(255,255,255,.06);
  margin-bottom: 5px;
  overflow: hidden;
  border: 1px solid transparent;
  transition: border-color .2s;
}
.pd-child-item.active { background: rgba(255,255,255,.13); border-color: rgba(255,255,255,.18); }

.pd-child-main {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  border: 0;
  background: transparent;
  color: rgba(255,255,255,.85);
  padding: 7px 8px;
  cursor: pointer;
  text-align: left;
  font-size: 12.5px;
  font-family: inherit;
  font-weight: 500;
}

.pd-child-avatar {
  width: 24px; height: 24px;
  border-radius: 50%;
  background: var(--pd-green-mid);
  color: var(--pd-green-deep);
  display: flex; align-items: center; justify-content: center;
  font-size: 10px; font-weight: 800;
  flex-shrink: 0;
}

.pd-child-row-actions {
  display: flex;
  gap: 3px;
  padding: 0 7px 6px;
}

.pd-child-action-btn {
  flex: 1;
  border: 1px solid rgba(255,255,255,.18);
  border-radius: 6px;
  background: rgba(255,255,255,.08);
  color: rgba(255,255,255,.7);
  padding: 3px 6px;
  cursor: pointer;
  font-size: 11px;
  transition: background .18s;
  font-family: inherit;
}
.pd-child-action-btn:hover { background: rgba(255,255,255,.18); color: #fff; }
.pd-child-action-btn--danger { background: rgba(220,38,38,.2); border-color: rgba(248,113,113,.4); }

/* Edit form */
.pd-child-edit-form {
  padding: 0 7px 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.pd-child-edit-form input,
.pd-child-edit-form select {
  width: 100%;
  border: 1px solid rgba(255,255,255,.25);
  border-radius: 6px;
  background: rgba(255,255,255,.1);
  color: #fff;
  padding: 6px 8px;
  font-size: 12px;
  font-family: inherit;
}
.pd-child-edit-form select option { color: #0f2318; }
.pd-child-edit-actions { display: flex; gap: 5px; }
.pd-child-edit-actions button {
  flex: 1;
  border: 0;
  border-radius: 6px;
  padding: 6px 8px;
  cursor: pointer;
  font-size: 11.5px;
  font-family: inherit;
  font-weight: 600;
}
.pd-child-edit-actions button:first-child { background: var(--pd-green); color: #fff; }
.pd-child-edit-actions button:last-child { background: rgba(255,255,255,.12); color: rgba(255,255,255,.75); }

/* Create form */
.pd-create-form {
  padding: 10px 8px 4px;
  border-top: 1px solid rgba(255,255,255,.07);
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.pd-create-form h5 {
  margin: 0 0 2px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: .7px;
  color: rgba(255,255,255,.38);
  text-transform: uppercase;
}
.pd-create-form input,
.pd-create-form select {
  width: 100%;
  border: 1px solid rgba(255,255,255,.22);
  border-radius: 7px;
  background: rgba(255,255,255,.1);
  color: #fff;
  padding: 8px 10px;
  font-size: 12.5px;
  font-family: inherit;
}
.pd-create-form input::placeholder { color: rgba(255,255,255,.42); }
.pd-create-form select option { color: #0f2318; }
.pd-create-form button {
  border: 0;
  border-radius: 8px;
  background: #fff;
  color: var(--pd-green-dark);
  padding: 9px 12px;
  font-weight: 700;
  font-size: 12.5px;
  cursor: pointer;
  font-family: inherit;
  transition: background .18s, transform .15s;
  box-shadow: 0 2px 8px rgba(0,0,0,.1);
}
.pd-create-form button:hover:not(:disabled) { background: var(--pd-green-light); transform: translateY(-1px); }
.pd-create-form button:disabled { opacity: .6; cursor: not-allowed; }

/* Sidebar footer */
.pd-sidebar__footer {
  padding: 12px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  flex-shrink: 0;
}
.pd-logout-btn {
  width: 100%;
  padding: 10px 13px;
  border-radius: 10px;
  border: 1px solid rgba(239,68,68,.28);
  background: rgba(239,68,68,.07);
  color: #fca5a5;
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all .18s;
}
.pd-logout-btn:hover { background: rgba(239,68,68,.18); color: #fecaca; }

/* ═══════════════════════════════════════════════
   MAIN — offset by sidebar width (like adm-main)
═══════════════════════════════════════════════ */
.pd-main {
  margin-left: var(--pd-sidebar-w);
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* ── Topbar (sticky, like adm-topbar) ── */
.pd-topbar {
  background: rgba(255,255,255,.92);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--pd-border);
  padding: 0 28px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 50;
  flex-shrink: 0;
  gap: 16px;
}

.pd-topbar__left { flex: 1; min-width: 0; }
.pd-topbar__breadcrumb { font-size: 11.5px; color: var(--pd-text-light); font-weight: 500; margin-bottom: 2px; }
.pd-topbar__title { font-size: 19px; font-weight: 800; color: var(--pd-text-dark); margin: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.pd-topbar__right { display: flex; align-items: center; gap: 12px; flex-shrink: 0; }

.pd-child-select {
  display: flex;
  align-items: center;
  gap: 8px;
}
.pd-child-select label {
  font-size: 13px;
  font-weight: 600;
  color: var(--pd-text-light);
  white-space: nowrap;
}
.pd-child-select select {
  padding: 8px 12px;
  border-radius: 9px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-text-dark);
  font-size: 13px;
  font-family: inherit;
  font-weight: 500;
  cursor: pointer;
  min-width: 170px;
}

/* ── Content area ── */
.pd-content {
  flex: 1;
  padding: 26px 30px;
  overflow-y: auto;
}

/* ── Hero banner ── */
.pd-hero {
  background: rgba(255,255,255,.13);
  border: 1px solid rgba(255,255,255,.18);
  backdrop-filter: blur(6px);
  border-radius: 16px;
  padding: 18px 22px;
  color: #fff;
  margin-bottom: 22px;
}
.pd-hero h2 { margin: 0; font-size: 20px; font-weight: 800; }
.pd-hero p { margin: 6px 0 0; color: rgba(255,255,255,.72); font-size: 13.5px; }

/* ── Section title ── */
.pd-section-h2 {
  font-size: 17px;
  font-weight: 800;
  color: #fff;
  margin: 0 0 18px;
}

/* ── Stat cards ── */
.pd-stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
  gap: 14px;
  margin-bottom: 20px;
}
.pd-stat-card {
  background: var(--pd-white);
  border-radius: 14px;
  padding: 20px;
  text-align: center;
  border: 1.5px solid var(--pd-border);
  box-shadow: var(--pd-shadow);
  transition: transform .2s, box-shadow .2s;
}
.pd-stat-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(0,166,81,.15); }
.pd-stat-icon { font-size: 30px; margin-bottom: 8px; }
.pd-stat-label { color: var(--pd-text-light); font-size: 12.5px; font-weight: 500; margin-bottom: 4px; }
.pd-stat-value { font-size: 30px; font-weight: 800; color: var(--pd-green-dark); }

/* ── White panel ── */
.pd-panel {
  background: var(--pd-white);
  border-radius: 16px;
  padding: 20px;
  border: 1.5px solid var(--pd-border);
  box-shadow: var(--pd-shadow);
}
.pd-panel h3 { margin: 0 0 12px; color: var(--pd-text-dark); font-weight: 700; font-size: 15px; }

/* ── Empty inline ── */
.pd-empty-inline {
  padding: 14px;
  background: var(--pd-green-light);
  border: 1px dashed var(--pd-green-mid);
  border-radius: 10px;
  color: var(--pd-text-light);
  font-size: 13.5px;
}

/* ── KPI grid ── */
.pd-kpi-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
  margin-bottom: 20px;
}
.pd-kpi {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 14px;
  padding: 16px;
  box-shadow: var(--pd-shadow);
  transition: transform .2s;
}
.pd-kpi:hover { transform: translateY(-3px); }
.pd-kpi-icon {
  width: 34px; height: 34px;
  border-radius: 9px;
  background: var(--pd-green-light);
  display: flex; align-items: center; justify-content: center;
  font-size: 16px;
  margin-bottom: 10px;
}
.pd-kpi-val { font-size: 22px; font-weight: 800; color: var(--pd-text-dark); }
.pd-kpi-label { font-size: 12px; color: var(--pd-text-light); font-weight: 500; margin-top: 2px; }
.pd-kpi-change { font-size: 11px; margin-top: 6px; font-weight: 600; color: var(--pd-green-dark); }

/* ── Charts ── */
.pd-charts-row { display: grid; grid-template-columns: 1.4fr 1fr; gap: 14px; margin-bottom: 20px; }
.pd-chart-card {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 14px;
  padding: 18px;
  box-shadow: var(--pd-shadow);
}
.pd-chart-card h3 { font-size: 13px; color: var(--pd-text-dark); margin: 0 0 12px; font-weight: 700; }
.pd-chart-wrap { position: relative; }

/* ── Progress bars ── */
.pd-progress-list { display: flex; flex-direction: column; gap: 10px; }
.pd-prog-row { display: flex; align-items: center; gap: 10px; }
.pd-prog-label { font-size: 12px; color: var(--pd-text-dark); width: 160px; font-weight: 500; flex-shrink: 0; }
.pd-prog-bar-bg { flex: 1; height: 8px; background: var(--pd-green-light); border-radius: 999px; }
.pd-prog-bar { height: 100%; border-radius: inherit; transition: width .6s ease; }
.pd-prog-val { font-size: 12px; color: var(--pd-text-light); width: 36px; text-align: right; font-weight: 600; }

/* ── Notes ── */
.pd-notes-list { display: flex; flex-direction: column; gap: 12px; }
.pd-note-card {
  background: var(--pd-off-white);
  padding: 16px;
  border-radius: 12px;
  border: 1.5px solid var(--pd-border);
  border-left: 4px solid var(--pd-green);
}
.pd-note-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
.pd-note-header h3 { margin: 0; color: var(--pd-text-dark); font-size: 14px; font-weight: 700; }
.pd-note-header small { color: var(--pd-text-light); font-size: 12px; }
.pd-note-content { color: #4B7A62; font-size: 13.5px; line-height: 1.6; margin: 0; }

/* ── Coming soon ── */
.pd-coming-soon {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 16px;
  text-align: center;
  padding: 50px 30px;
  box-shadow: var(--pd-shadow);
}
.pd-coming-soon h2 { color: var(--pd-text-dark); font-weight: 800; margin-bottom: 12px; font-size: 20px; }
.pd-coming-soon p { color: var(--pd-text-light); font-size: 14px; }

/* ── Empty state (no children) ── */
.pd-empty-state {
  background: rgba(255,255,255,.13);
  border: 1px dashed rgba(255,255,255,.3);
  border-radius: 16px;
  padding: 40px 28px;
  text-align: center;
  color: rgba(255,255,255,.85);
  font-size: 14px;
  line-height: 1.6;
}

/* ── Invite professional ── */
.pd-invite-input {
  width: 100%;
  padding: 10px 13px;
  border: 1.5px solid var(--pd-border);
  border-radius: 10px;
  font-size: 14px;
  font-family: inherit;
  background: var(--pd-off-white);
  color: var(--pd-text-dark);
  transition: border-color .18s, box-shadow .18s;
}

.pd-invite-input:focus {
  outline: none;
  border-color: var(--pd-green);
  background: #fff;
  box-shadow: 0 0 0 4px rgba(0,166,81,.12);
}

.pd-invite-error {
  font-size: 13px;
  color: #b91c1c;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 9px;
  padding: 10px 14px;
  font-weight: 500;
}

.pd-invite-btn {
  padding: 11px 22px;
  border-radius: 10px;
  border: none;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  color: #fff;
  font-size: 14px;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  box-shadow: 0 4px 14px rgba(0,166,81,.35);
  transition: all .18s;
}

.pd-invite-btn:hover:not(:disabled) { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(0,166,81,.5); }
.pd-invite-btn:disabled { opacity: .55; cursor: not-allowed; transform: none; }

.pd-invite-success {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-green-mid);
  border-left: 4px solid var(--pd-green);
  border-radius: 14px;
  padding: 22px;
  display: flex;
  gap: 16px;
  box-shadow: var(--pd-shadow);
}

.pd-invite-success__icon { font-size: 28px; flex-shrink: 0; }

.pd-invite-success__body { flex: 1; }

.pd-invite-success__body h4 {
  margin: 0 0 8px;
  font-size: 15px;
  font-weight: 700;
  color: var(--pd-text-dark);
}

.pd-invite-success__body p {
  font-size: 13.5px;
  color: var(--pd-text-light);
  line-height: 1.6;
  margin: 0 0 14px;
}

.pd-invite-link-box {
  background: var(--pd-green-light);
  border: 1px solid var(--pd-green-mid);
  border-radius: 9px;
  padding: 12px 14px;
}

.pd-invite-new-btn {
  margin-top: 14px;
  padding: 8px 16px;
  border-radius: 9px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-green-dark);
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background .18s;
}

.pd-invite-new-btn:hover { background: var(--pd-green-light); border-color: var(--pd-green-mid); }

/* ── Professional list ── */
.pd-prof-list { display: flex; flex-direction: column; gap: 10px; }

.pd-prof-item {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 16px;
  background: var(--pd-off-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 12px;
  transition: box-shadow .2s;
}
.pd-prof-item:hover { box-shadow: 0 3px 14px rgba(0,122,58,.1); }

.pd-prof-avatar {
  width: 42px; height: 42px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  color: #fff;
  font-size: 16px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.pd-prof-info { flex: 1; overflow: hidden; }
.pd-prof-info strong { display: block; font-size: 14px; font-weight: 700; color: var(--pd-text-dark); }
.pd-prof-info span  { display: block; font-size: 12.5px; color: var(--pd-text-light); margin-top: 1px; }
.pd-prof-info small { display: block; font-size: 11px; color: #aabfb5; margin-top: 2px; }

.pd-prof-badge {
  font-size: 12px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: 20px;
  flex-shrink: 0;
}
.pd-prof-badge--active  { background: #dcfce7; color: #166534; }
.pd-prof-badge--pending { background: #fef9c3; color: #854d0e; }
.pd-prof-badge--revoked { background: #fee2e2; color: #991b1b; }

.pd-prof-actions { display: flex; gap: 6px; flex-shrink: 0; }

.pd-prof-btn {
  padding: 7px 13px;
  border-radius: 8px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-green-dark);
  font-size: 12px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: all .18s;
  white-space: nowrap;
}
.pd-prof-btn:hover:not(:disabled) { background: var(--pd-green-light); border-color: var(--pd-green-mid); }
.pd-prof-btn--danger { background: #fef2f2; color: #b91c1c; border-color: #fecaca; }
.pd-prof-btn--danger:hover:not(:disabled) { background: #fee2e2; }
.pd-prof-btn:disabled { opacity: .55; cursor: not-allowed; }

/* ── Inline action message ── */
.pd-action-msg {
  padding: 12px 16px;
  border-radius: 10px;
  font-size: 13.5px;
  font-weight: 500;
  margin-bottom: 16px;
}
.pd-action-msg--success { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
.pd-action-msg--error   { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }

/* ════════════════════════════
   INVITATION CARDS WITH STEPS
════════════════════════════ */
.pd-inv-list { display: flex; flex-direction: column; gap: 16px; }

.pd-inv-card {
  background: var(--pd-white);
  border: 1.5px solid var(--pd-border);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--pd-shadow);
  transition: box-shadow .2s;
}
.pd-inv-card:hover { box-shadow: 0 6px 24px rgba(0,122,58,.14); }
.pd-inv-card--revoked { border-color: #fecaca; opacity: .85; }
.pd-inv-card--active  { border-color: var(--pd-green-mid); }

/* Card header */
.pd-inv-card__head {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 16px 20px;
  border-bottom: 1px solid var(--pd-border);
  background: var(--pd-off-white);
}
.pd-inv-card__avatar {
  width: 46px; height: 46px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--pd-green-dark), var(--pd-green));
  color: #fff;
  font-size: 18px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}
.pd-inv-card__info { flex: 1; }
.pd-inv-card__info strong { display: block; font-size: 15px; font-weight: 700; color: var(--pd-text-dark); }
.pd-inv-card__info span  { font-size: 13px; color: var(--pd-text-light); }
.pd-inv-card__date { font-size: 11.5px; color: #aabfb5; white-space: nowrap; }

/* Steps */
.pd-inv-steps {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding: 16px 20px;
}

.pd-inv-step {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  padding: 11px 14px;
  border-radius: 10px;
  background: #f8fafb;
  border: 1.5px solid #eef2ef;
  margin-bottom: 8px;
}
.pd-inv-step:last-child { margin-bottom: 0; }

.pd-inv-step--done {
  background: var(--pd-green-light);
  border-color: var(--pd-green-mid);
}
.pd-inv-step--active {
  background: #fffbeb;
  border-color: #fde68a;
}
.pd-inv-step--revoked {
  background: #fef2f2;
  border-color: #fecaca;
}

.pd-inv-step__circle {
  width: 28px; height: 28px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 12px; font-weight: 700;
  flex-shrink: 0;
  background: var(--pd-green);
  color: #fff;
}
.pd-inv-step__circle--pulse {
  background: #f59e0b;
  animation: pd-pulse-step 1.8s ease-in-out infinite;
}
.pd-inv-step__circle--muted  { background: #d1d5db; }
.pd-inv-step__circle--danger { background: #ef4444; }

@keyframes pd-pulse-step {
  0%, 100% { box-shadow: 0 0 0 0 rgba(245,158,11,.4); }
  50%       { box-shadow: 0 0 0 6px rgba(245,158,11,0); }
}

.pd-inv-step__text { flex: 1; }
.pd-inv-step__label {
  font-size: 13px; font-weight: 600;
  color: var(--pd-text-dark);
  margin-bottom: 2px;
}
.pd-inv-step__desc  { font-size: 12px; color: var(--pd-text-light); }

/* Card actions */
.pd-inv-card__actions {
  display: flex;
  gap: 10px;
  padding: 14px 20px;
  border-top: 1px solid var(--pd-border);
  background: var(--pd-off-white);
}

.pd-inv-btn {
  padding: 9px 18px;
  border-radius: 9px;
  border: 1.5px solid var(--pd-border);
  background: var(--pd-white);
  color: var(--pd-green-dark);
  font-size: 13px; font-weight: 600;
  font-family: inherit; cursor: pointer;
  transition: all .18s;
  white-space: nowrap;
}
.pd-inv-btn:hover:not(:disabled) { background: var(--pd-green-light); border-color: var(--pd-green-mid); }
.pd-inv-btn--danger  { background: #fef2f2; color: #b91c1c; border-color: #fecaca; }
.pd-inv-btn--danger:hover:not(:disabled) { background: #fee2e2; }
.pd-inv-btn--restore { background: var(--pd-green-light); color: var(--pd-green-dark); border-color: var(--pd-green-mid); }
.pd-inv-btn--restore:hover:not(:disabled) { background: var(--pd-green-mid); }
.pd-inv-btn:disabled { opacity: .55; cursor: not-allowed; }

/* ── Responsive ── */
@media (max-width: 900px) {
  .pd-layout { flex-direction: column; }
  .pd-sidebar {
    position: relative;
    width: 100%;
    top: auto; left: auto; bottom: auto;
  }
  .pd-main { margin-left: 0; }
  .pd-topbar { height: auto; padding: 14px 18px; flex-direction: column; align-items: flex-start; gap: 10px; }
  .pd-topbar__right { width: 100%; }
  .pd-child-select { width: 100%; }
  .pd-child-select select { flex: 1; }
  .pd-content { padding: 16px 18px; }
  .pd-kpi-grid { grid-template-columns: repeat(2, 1fr); }
  .pd-charts-row { grid-template-columns: 1fr; }
}

@media (max-width: 600px) {
  .pd-kpi-grid { grid-template-columns: 1fr; }
  .pd-stats-grid { grid-template-columns: 1fr; }
}

/* ============================================================ */
/* PROFESSIONAL DASHBOARD — Pharmacy Green Design              */
/* Prefix: prof-                                               */
/* ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

:root {
  --prof-green:        #00A651;
  --prof-green-dark:   #007A3A;
  --prof-green-deep:   #00572A;
  --prof-green-light:  #E6F7EE;
  --prof-green-mid:    #C2EAD4;
  --prof-sidebar-bg:   #013D1C;
  --prof-sidebar-w:    280px;
  --prof-white:        #FFFFFF;
  --prof-off-white:    #F4FAF7;
  --prof-text-dark:    #0F2318;
  --prof-text-light:   #7A9485;
  --prof-border:       #D1E8DB;
  --prof-shadow:       0 4px 24px rgba(0,122,58,.12);
}

* { box-sizing: border-box; }

/* ── Layout ── */
.prof-layout {
  display: flex;
  min-height: 100vh;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #EAFFF5;
}

/* ══════════════════════════════════════════════════
   SIDEBAR
══════════════════════════════════════════════════ */
.prof-sidebar {
  width: var(--prof-sidebar-w);
  background: var(--prof-sidebar-bg);
  display: flex;
  flex-direction: column;
  position: fixed;
  top: 0; left: 0; bottom: 0;
  z-index: 100;
  overflow-y: auto;
  overflow-x: hidden;
}

.prof-sidebar::-webkit-scrollbar { width: 4px; }
.prof-sidebar::-webkit-scrollbar-track { background: transparent; }
.prof-sidebar::-webkit-scrollbar-thumb { background: rgba(255,255,255,.12); border-radius: 2px; }

/* Brand */
.prof-sidebar__brand {
  padding: 22px 18px 18px;
  border-bottom: 1px solid rgba(255,255,255,.07);
  display: flex;
  align-items: center;
  gap: 11px;
  flex-shrink: 0;
}

.prof-sidebar__logo {
  width: 40px; height: 40px;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}

.prof-sidebar__brand-text h2 {
  color: #fff;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: -.3px;
  margin: 0;
}

.prof-sidebar__brand-text span {
  color: rgba(255,255,255,.38);
  font-size: 10.5px;
  letter-spacing: .7px;
  text-transform: uppercase;
}

/* Nav */
.prof-sidebar__nav {
  padding: 14px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex-shrink: 0;
}

.prof-nav__label {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 10px 8px 5px;
}

.prof-nav__item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 13px;
  border-radius: 10px;
  cursor: pointer;
  border: none;
  background: transparent;
  color: rgba(255,255,255,.52);
  font-size: 13.5px;
  font-weight: 500;
  font-family: inherit;
  text-align: left;
  width: 100%;
  transition: all .18s;
}

.prof-nav__item .nav-icon { font-size: 16px; flex-shrink: 0; }

.prof-nav__item:hover { background: rgba(255,255,255,.06); color: rgba(255,255,255,.9); }

.prof-nav__item.active {
  background: linear-gradient(90deg, rgba(0,166,81,.3), rgba(0,166,81,.12));
  color: #fff;
  border-left: 3px solid var(--prof-green);
  font-weight: 600;
}

/* Patients section */
.prof-sidebar__patients {
  padding: 0 10px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  margin-top: 4px;
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}

.prof-sidebar__patients::-webkit-scrollbar { width: 3px; }
.prof-sidebar__patients::-webkit-scrollbar-thumb { background: rgba(255,255,255,.1); border-radius: 2px; }

.prof-section-title {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 12px 8px 6px;
}

/* Search */
.prof-search-wrap { padding: 0 0 8px; }

.prof-search {
  width: 100%;
  padding: 7px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,.2);
  background: rgba(255,255,255,.09);
  color: #fff;
  font-size: 12.5px;
  font-family: inherit;
  outline: none;
}

.prof-search::placeholder { color: rgba(255,255,255,.38); }
.prof-search:focus { border-color: rgba(0,166,81,.6); background: rgba(255,255,255,.13); }

/* Patient item */
.prof-patient-item {
  display: flex;
  align-items: center;
  gap: 9px;
  width: 100%;
  border: 1px solid transparent;
  border-radius: 9px;
  background: rgba(255,255,255,.06);
  color: rgba(255,255,255,.75);
  padding: 8px 9px;
  cursor: pointer;
  text-align: left;
  font-size: 12.5px;
  font-family: inherit;
  margin-bottom: 4px;
  transition: all .18s;
}

.prof-patient-item:hover { background: rgba(255,255,255,.12); color: #fff; }

.prof-patient-item.active {
  background: rgba(255,255,255,.14);
  border-color: rgba(255,255,255,.22);
  color: #fff;
}

.prof-patient-avatar {
  width: 28px; height: 28px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 11px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-patient-name {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.prof-patient-name small {
  color: rgba(255,255,255,.42);
  font-size: 10.5px;
  white-space: nowrap;
}

.prof-no-patients {
  color: rgba(255,255,255,.35);
  font-size: 12px;
  text-align: center;
  padding: 12px 8px;
}

/* Sidebar footer */
.prof-sidebar__footer {
  padding: 12px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  flex-shrink: 0;
}

.prof-sidebar__user {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 8px;
  border-radius: 10px;
  margin-bottom: 8px;
}

.prof-sidebar__avatar {
  width: 34px; height: 34px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 13px; font-weight: 700;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-sidebar__user-info { flex: 1; overflow: hidden; }
.prof-sidebar__user-name { color: #fff; font-size: 13px; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.prof-sidebar__user-role { color: rgba(255,255,255,.38); font-size: 11px; }

.prof-logout-btn {
  width: 100%;
  padding: 10px 13px;
  border-radius: 10px;
  border: 1px solid rgba(239,68,68,.28);
  background: rgba(239,68,68,.07);
  color: #fca5a5;
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all .18s;
}

.prof-logout-btn:hover { background: rgba(239,68,68,.18); color: #fecaca; }

/* ══════════════════════════════════════════════════
   MAIN
══════════════════════════════════════════════════ */
.prof-main {
  margin-left: var(--prof-sidebar-w);
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* Topbar */
.prof-topbar {
  background: rgba(255,255,255,.93);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--prof-border);
  padding: 0 28px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 50;
  gap: 16px;
  flex-shrink: 0;
}

.prof-topbar__left { flex: 1; min-width: 0; }
.prof-topbar__breadcrumb { font-size: 11.5px; color: var(--prof-text-light); margin-bottom: 2px; font-weight: 500; }
.prof-topbar__left h1 { font-size: 19px; font-weight: 800; color: var(--prof-text-dark); margin: 0; }
.prof-topbar__right { display: flex; align-items: center; gap: 12px; flex-shrink: 0; }

.prof-patient-select { display: flex; align-items: center; gap: 8px; }
.prof-patient-select label { font-size: 13px; font-weight: 600; color: var(--prof-text-light); white-space: nowrap; }
.prof-patient-select select {
  padding: 8px 12px;
  border-radius: 9px;
  border: 1.5px solid var(--prof-border);
  background: var(--prof-white);
  color: var(--prof-text-dark);
  font-size: 13px; font-family: inherit; font-weight: 500;
  cursor: pointer; min-width: 180px;
}

/* Content area */
.prof-content {
  flex: 1;
  padding: 26px 30px;
  overflow-y: auto;
  background: #EAFFF5;
}

/* ── KPIs ── */
.prof-kpis {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(155px, 1fr));
  gap: 14px;
  margin-bottom: 24px;
}

.prof-kpi {
  background: var(--prof-white);
  border: 1px solid var(--prof-border);
  border-radius: 14px;
  padding: 18px;
  display: flex;
  align-items: center;
  gap: 14px;
  box-shadow: var(--prof-shadow);
  transition: transform .2s, box-shadow .2s;
}

.prof-kpi:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,122,58,.16); }

.prof-kpi__icon {
  width: 44px; height: 44px;
  border-radius: 11px;
  background: var(--prof-green-light);
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}

.prof-kpi__val { font-size: 26px; font-weight: 800; color: var(--prof-text-dark); display: block; margin-bottom: 2px; line-height: 1; }
.prof-kpi__lbl { font-size: 11.5px; color: var(--prof-text-light); font-weight: 500; }

/* ── Section card ── */
.prof-section {
  background: var(--prof-white);
  border: 1px solid var(--prof-border);
  border-radius: 14px;
  box-shadow: var(--prof-shadow);
  overflow: hidden;
}

.prof-section__head {
  padding: 18px 22px;
  border-bottom: 1px solid var(--prof-border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--prof-off-white);
}

.prof-section__head h2 { font-size: 15px; font-weight: 700; color: var(--prof-text-dark); margin: 0; }

.prof-section__count {
  font-size: 12px;
  background: var(--prof-green-light);
  color: var(--prof-green-dark);
  border: 1px solid var(--prof-green-mid);
  border-radius: 20px;
  padding: 3px 10px;
  font-weight: 600;
}

.prof-section__body { padding: 22px; }

/* ── Empty / loading ── */
.prof-empty { text-align: center; padding: 48px 24px; color: var(--prof-text-light); }
.prof-empty__icon { font-size: 48px; margin-bottom: 14px; }
.prof-empty p { font-size: 14px; font-weight: 500; }

.prof-empty-state {
  background: rgba(0,166,81,.07);
  border: 1px dashed var(--prof-green-mid);
  border-radius: 16px;
  padding: 40px 28px;
  text-align: center;
  color: var(--prof-text-light);
  font-size: 14px;
  line-height: 1.7;
}

.prof-loading {
  text-align: center;
  padding: 80px 24px;
  color: var(--prof-text-light);
}

.prof-loading__spinner {
  width: 36px; height: 36px;
  border: 3px solid var(--prof-green-mid);
  border-top-color: var(--prof-green);
  border-radius: 50%;
  animation: prof-spin .8s linear infinite;
  margin: 0 auto 16px;
}

@keyframes prof-spin { to { transform: rotate(360deg); } }

/* ── Patient card ── */
.prof-patient-card {
  display: flex;
  gap: 24px;
  align-items: flex-start;
}

.prof-patient-card__avatar {
  width: 72px; height: 72px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 28px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-patient-card__details { flex: 1; }

.prof-patient-card__details h3 {
  font-size: 20px;
  font-weight: 800;
  color: var(--prof-text-dark);
  margin: 0 0 16px;
}

.prof-patient-card__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
}

.prof-patient-card__item {
  background: var(--prof-off-white);
  border: 1px solid var(--prof-border);
  border-radius: 10px;
  padding: 12px 14px;
}

.prof-patient-card__item label {
  display: block;
  font-size: 10.5px;
  font-weight: 700;
  color: var(--prof-text-light);
  text-transform: uppercase;
  letter-spacing: .5px;
  margin-bottom: 5px;
}

.prof-patient-card__item span { font-size: 16px; font-weight: 700; color: var(--prof-text-dark); }

/* ── Table ── */
.prof-table-wrap {
  border: 1px solid var(--prof-border);
  border-radius: 12px;
  overflow: hidden;
  margin: 0;
}

.prof-table { width: 100%; border-collapse: collapse; }

.prof-table thead { background: var(--prof-green-light); }

.prof-table th {
  padding: 12px 16px;
  text-align: left;
  font-size: 11.5px;
  font-weight: 700;
  color: var(--prof-green-dark);
  text-transform: uppercase;
  letter-spacing: .4px;
  white-space: nowrap;
}

.prof-table td {
  padding: 13px 16px;
  border-bottom: 1px solid #f0f7f3;
  font-size: 13.5px;
  color: var(--prof-text-dark);
  vertical-align: middle;
}

.prof-table tbody tr:last-child td { border-bottom: none; }
.prof-table tbody tr:hover { background: rgba(0,166,81,.03); }

/* Score badge */
.prof-score-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 700;
}

.prof-score-badge--good { background: #dcfce7; color: #166534; }
.prof-score-badge--mid  { background: #fef9c3; color: #854d0e; }
.prof-score-badge--low  { background: #fee2e2; color: #991b1b; }

/* ── Note form ── */
.prof-note-form { display: flex; flex-direction: column; gap: 14px; }

.prof-note-textarea {
  width: 100%;
  padding: 13px 16px;
  border: 1.5px solid var(--prof-border);
  border-radius: 12px;
  font-size: 14px;
  font-family: inherit;
  background: var(--prof-off-white);
  color: var(--prof-text-dark);
  resize: vertical;
  transition: border-color .18s, box-shadow .18s;
  line-height: 1.6;
}

.prof-note-textarea:focus {
  outline: none;
  border-color: var(--prof-green);
  background: #fff;
  box-shadow: 0 0 0 4px rgba(0,166,81,.12);
}

/* ── Buttons ── */
.prof-btn {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 11px 20px;
  border-radius: 10px;
  font-size: 14px;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  border: none;
  transition: all .18s;
  align-self: flex-start;
}

.prof-btn--primary {
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  box-shadow: 0 4px 14px rgba(0,166,81,.35);
}

.prof-btn--primary:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(0,166,81,.5);
}

.prof-btn:disabled { opacity: .55; cursor: not-allowed; transform: none !important; }

/* ── Notes list ── */
.prof-notes-list { display: flex; flex-direction: column; gap: 12px; }

.prof-note-card {
  background: var(--prof-off-white);
  border: 1.5px solid var(--prof-border);
  border-left: 4px solid var(--prof-green);
  border-radius: 12px;
  padding: 16px;
  transition: box-shadow .2s;
}

.prof-note-card:hover { box-shadow: 0 4px 16px rgba(0,122,58,.1); }

.prof-note-card__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.prof-note-card__author { font-size: 13px; font-weight: 700; color: var(--prof-green-dark); }
.prof-note-card__date   { font-size: 11.5px; color: var(--prof-text-light); }
.prof-note-card__content { font-size: 13.5px; color: #4B7A62; line-height: 1.65; margin: 0; }

/* ── Coming soon ── */
.prof-coming-soon {
  background: var(--prof-white);
  border: 1.5px solid var(--prof-border);
  border-radius: 16px;
  text-align: center;
  padding: 60px 30px;
  box-shadow: var(--prof-shadow);
}

.prof-coming-soon__icon { font-size: 56px; margin-bottom: 16px; }
.prof-coming-soon h2 { color: var(--prof-text-dark); font-size: 22px; font-weight: 800; margin: 0 0 10px; }
.prof-coming-soon p { color: var(--prof-text-light); font-size: 14px; line-height: 1.7; margin: 0; }

/* ── Toast ── */
.prof-toast-wrap {
  position: fixed;
  bottom: 24px; right: 24px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  z-index: 9999;
}

.prof-toast {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 18px;
  border-radius: 12px;
  min-width: 280px; max-width: 380px;
  box-shadow: 0 8px 28px rgba(0,0,0,.15);
  animation: prof-toast-in .3s cubic-bezier(.34,1.56,.64,1);
  font-size: 13.5px;
  font-weight: 500;
}

@keyframes prof-toast-in {
  from { opacity: 0; transform: translateY(20px) scale(.95); }
  to   { opacity: 1; transform: translateY(0) scale(1); }
}

.prof-toast--success { background: #fff; border-left: 4px solid var(--prof-green); color: var(--prof-text-dark); }
.prof-toast--error   { background: #fff; border-left: 4px solid #E53935; color: var(--prof-text-dark); }
.prof-toast__icon  { font-size: 18px; flex-shrink: 0; }
.prof-toast__msg   { flex: 1; }
.prof-toast__close { background: none; border: none; cursor: pointer; color: var(--prof-text-light); font-size: 16px; padding: 0; line-height: 1; }

/* ── Responsive ── */
@media (max-width: 900px) {
  .prof-sidebar { transform: translateX(-100%); }
  .prof-main { margin-left: 0; }
  .prof-content { padding: 16px; }
  .prof-kpis { grid-template-columns: repeat(2, 1fr); }
  .prof-patient-card { flex-direction: column; }
  .prof-patient-card__grid { grid-template-columns: repeat(2, 1fr); }
  .prof-topbar { height: auto; padding: 14px 18px; flex-wrap: wrap; }
}

@media (max-width: 600px) {
  .prof-kpis { grid-template-columns: 1fr; }
  .prof-patient-card__grid { grid-template-columns: 1fr; }
}

/* ============================================================ */
/* PROFESSIONAL DASHBOARD — Pharmacy Green Design              */
/* Prefix: prof-                                               */
/* ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

:root {
  --prof-green:        #00A651;
  --prof-green-dark:   #007A3A;
  --prof-green-deep:   #00572A;
  --prof-green-light:  #E6F7EE;
  --prof-green-mid:    #C2EAD4;
  --prof-sidebar-bg:   #013D1C;
  --prof-sidebar-w:    280px;
  --prof-white:        #FFFFFF;
  --prof-off-white:    #F4FAF7;
  --prof-text-dark:    #0F2318;
  --prof-text-light:   #7A9485;
  --prof-border:       #D1E8DB;
  --prof-shadow:       0 4px 24px rgba(0,122,58,.12);
}

* { box-sizing: border-box; }

/* ── Layout ── */
.prof-layout {
  display: flex;
  min-height: 100vh;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #EAFFF5;
}

/* ══════════════════════════════════════════════════
   SIDEBAR
══════════════════════════════════════════════════ */
.prof-sidebar {
  width: var(--prof-sidebar-w);
  background: var(--prof-sidebar-bg);
  display: flex;
  flex-direction: column;
  position: fixed;
  top: 0; left: 0; bottom: 0;
  z-index: 100;
  overflow-y: auto;
  overflow-x: hidden;
}

.prof-sidebar::-webkit-scrollbar { width: 4px; }
.prof-sidebar::-webkit-scrollbar-track { background: transparent; }
.prof-sidebar::-webkit-scrollbar-thumb { background: rgba(255,255,255,.12); border-radius: 2px; }

/* Brand */
.prof-sidebar__brand {
  padding: 22px 18px 18px;
  border-bottom: 1px solid rgba(255,255,255,.07);
  display: flex;
  align-items: center;
  gap: 11px;
  flex-shrink: 0;
}

.prof-sidebar__logo {
  width: 40px; height: 40px;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}

.prof-sidebar__brand-text h2 {
  color: #fff;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: -.3px;
  margin: 0;
}

.prof-sidebar__brand-text span {
  color: rgba(255,255,255,.38);
  font-size: 10.5px;
  letter-spacing: .7px;
  text-transform: uppercase;
}

/* Nav */
.prof-sidebar__nav {
  padding: 14px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex-shrink: 0;
}

.prof-nav__label {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 10px 8px 5px;
}

.prof-nav__item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 13px;
  border-radius: 10px;
  cursor: pointer;
  border: none;
  background: transparent;
  color: rgba(255,255,255,.52);
  font-size: 13.5px;
  font-weight: 500;
  font-family: inherit;
  text-align: left;
  width: 100%;
  transition: all .18s;
}

.prof-nav__item .nav-icon { font-size: 16px; flex-shrink: 0; }

.prof-nav__item:hover { background: rgba(255,255,255,.06); color: rgba(255,255,255,.9); }

.prof-nav__item.active {
  background: linear-gradient(90deg, rgba(0,166,81,.3), rgba(0,166,81,.12));
  color: #fff;
  border-left: 3px solid var(--prof-green);
  font-weight: 600;
}

/* Nav badge */
.prof-nav__badge {
  margin-left: auto;
  background: var(--prof-green);
  color: #fff;
  font-size: 10.5px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 20px;
  min-width: 18px;
  text-align: center;
}

/* Patients section */
.prof-sidebar__patients {
  padding: 0 10px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  margin-top: 4px;
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}

.prof-sidebar__patients::-webkit-scrollbar { width: 3px; }
.prof-sidebar__patients::-webkit-scrollbar-thumb { background: rgba(255,255,255,.1); border-radius: 2px; }

.prof-section-title {
  color: rgba(255,255,255,.28);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 12px 8px 6px;
}

/* Search */
.prof-search-wrap { padding: 0 0 8px; }

.prof-search {
  width: 100%;
  padding: 7px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,.2);
  background: rgba(255,255,255,.09);
  color: #fff;
  font-size: 12.5px;
  font-family: inherit;
  outline: none;
}

.prof-search::placeholder { color: rgba(255,255,255,.38); }
.prof-search:focus { border-color: rgba(0,166,81,.6); background: rgba(255,255,255,.13); }

/* Patient item */
.prof-patient-item {
  display: flex;
  align-items: center;
  gap: 9px;
  width: 100%;
  border: 1px solid transparent;
  border-radius: 9px;
  background: rgba(255,255,255,.06);
  color: rgba(255,255,255,.75);
  padding: 8px 9px;
  cursor: pointer;
  text-align: left;
  font-size: 12.5px;
  font-family: inherit;
  margin-bottom: 4px;
  transition: all .18s;
}

.prof-patient-item:hover { background: rgba(255,255,255,.12); color: #fff; }

.prof-patient-item.active {
  background: rgba(255,255,255,.14);
  border-color: rgba(255,255,255,.22);
  color: #fff;
}

.prof-patient-avatar {
  width: 28px; height: 28px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 11px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-patient-name {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.prof-patient-name small {
  color: rgba(255,255,255,.42);
  font-size: 10.5px;
  white-space: nowrap;
}

.prof-no-patients {
  color: rgba(255,255,255,.35);
  font-size: 12px;
  text-align: center;
  padding: 12px 8px;
}

/* Sidebar footer */
.prof-sidebar__footer {
  padding: 12px 10px;
  border-top: 1px solid rgba(255,255,255,.07);
  flex-shrink: 0;
}

.prof-sidebar__user {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 8px;
  border-radius: 10px;
  margin-bottom: 8px;
}

.prof-sidebar__avatar {
  width: 34px; height: 34px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 13px; font-weight: 700;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-sidebar__user-info { flex: 1; overflow: hidden; }
.prof-sidebar__user-name { color: #fff; font-size: 13px; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.prof-sidebar__user-role { color: rgba(255,255,255,.38); font-size: 11px; }

.prof-logout-btn {
  width: 100%;
  padding: 10px 13px;
  border-radius: 10px;
  border: 1px solid rgba(239,68,68,.28);
  background: rgba(239,68,68,.07);
  color: #fca5a5;
  font-size: 13px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all .18s;
}

.prof-logout-btn:hover { background: rgba(239,68,68,.18); color: #fecaca; }

/* ══════════════════════════════════════════════════
   MAIN
══════════════════════════════════════════════════ */
.prof-main {
  margin-left: var(--prof-sidebar-w);
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* Topbar */
.prof-topbar {
  background: rgba(255,255,255,.93);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--prof-border);
  padding: 0 28px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 50;
  gap: 16px;
  flex-shrink: 0;
}

.prof-topbar__left { flex: 1; min-width: 0; }
.prof-topbar__breadcrumb { font-size: 11.5px; color: var(--prof-text-light); margin-bottom: 2px; font-weight: 500; }
.prof-topbar__left h1 { font-size: 19px; font-weight: 800; color: var(--prof-text-dark); margin: 0; }
.prof-topbar__right { display: flex; align-items: center; gap: 12px; flex-shrink: 0; }

.prof-patient-select { display: flex; align-items: center; gap: 8px; }
.prof-patient-select label { font-size: 13px; font-weight: 600; color: var(--prof-text-light); white-space: nowrap; }
.prof-patient-select select {
  padding: 8px 12px;
  border-radius: 9px;
  border: 1.5px solid var(--prof-border);
  background: var(--prof-white);
  color: var(--prof-text-dark);
  font-size: 13px; font-family: inherit; font-weight: 500;
  cursor: pointer; min-width: 180px;
}

/* Content area */
.prof-content {
  flex: 1;
  padding: 26px 30px;
  overflow-y: auto;
  background: #EAFFF5;
}

/* ── KPIs ── */
.prof-kpis {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(155px, 1fr));
  gap: 14px;
  margin-bottom: 24px;
}

.prof-kpi {
  background: var(--prof-white);
  border: 1px solid var(--prof-border);
  border-radius: 14px;
  padding: 18px;
  display: flex;
  align-items: center;
  gap: 14px;
  box-shadow: var(--prof-shadow);
  transition: transform .2s, box-shadow .2s;
}

.prof-kpi:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,122,58,.16); }

.prof-kpi__icon {
  width: 44px; height: 44px;
  border-radius: 11px;
  background: var(--prof-green-light);
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}

.prof-kpi__val { font-size: 26px; font-weight: 800; color: var(--prof-text-dark); display: block; margin-bottom: 2px; line-height: 1; }
.prof-kpi__lbl { font-size: 11.5px; color: var(--prof-text-light); font-weight: 500; }

/* ── Section card ── */
.prof-section {
  background: var(--prof-white);
  border: 1px solid var(--prof-border);
  border-radius: 14px;
  box-shadow: var(--prof-shadow);
  overflow: hidden;
}

.prof-section__head {
  padding: 18px 22px;
  border-bottom: 1px solid var(--prof-border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--prof-off-white);
}

.prof-section__head h2 { font-size: 15px; font-weight: 700; color: var(--prof-text-dark); margin: 0; }

.prof-section__count {
  font-size: 12px;
  background: var(--prof-green-light);
  color: var(--prof-green-dark);
  border: 1px solid var(--prof-green-mid);
  border-radius: 20px;
  padding: 3px 10px;
  font-weight: 600;
}

.prof-section__body { padding: 22px; }

/* ── Empty / loading ── */
.prof-empty { text-align: center; padding: 48px 24px; color: var(--prof-text-light); }
.prof-empty__icon { font-size: 48px; margin-bottom: 14px; }
.prof-empty p { font-size: 14px; font-weight: 500; }

.prof-empty-state {
  background: rgba(0,166,81,.07);
  border: 1px dashed var(--prof-green-mid);
  border-radius: 16px;
  padding: 40px 28px;
  text-align: center;
  color: var(--prof-text-light);
  font-size: 14px;
  line-height: 1.7;
}

.prof-loading {
  text-align: center;
  padding: 80px 24px;
  color: var(--prof-text-light);
}

.prof-loading__spinner {
  width: 36px; height: 36px;
  border: 3px solid var(--prof-green-mid);
  border-top-color: var(--prof-green);
  border-radius: 50%;
  animation: prof-spin .8s linear infinite;
  margin: 0 auto 16px;
}

@keyframes prof-spin { to { transform: rotate(360deg); } }

/* ── Patient card ── */
.prof-patient-card {
  display: flex;
  gap: 24px;
  align-items: flex-start;
}

.prof-patient-card__avatar {
  width: 72px; height: 72px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 28px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.prof-patient-card__details { flex: 1; }

.prof-patient-card__details h3 {
  font-size: 20px;
  font-weight: 800;
  color: var(--prof-text-dark);
  margin: 0 0 16px;
}

.prof-patient-card__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
}

.prof-patient-card__item {
  background: var(--prof-off-white);
  border: 1px solid var(--prof-border);
  border-radius: 10px;
  padding: 12px 14px;
}

.prof-patient-card__item label {
  display: block;
  font-size: 10.5px;
  font-weight: 700;
  color: var(--prof-text-light);
  text-transform: uppercase;
  letter-spacing: .5px;
  margin-bottom: 5px;
}

.prof-patient-card__item span { font-size: 16px; font-weight: 700; color: var(--prof-text-dark); }

/* ── Table ── */
.prof-table-wrap {
  border: 1px solid var(--prof-border);
  border-radius: 12px;
  overflow: hidden;
  margin: 0;
}

.prof-table { width: 100%; border-collapse: collapse; }

.prof-table thead { background: var(--prof-green-light); }

.prof-table th {
  padding: 12px 16px;
  text-align: left;
  font-size: 11.5px;
  font-weight: 700;
  color: var(--prof-green-dark);
  text-transform: uppercase;
  letter-spacing: .4px;
  white-space: nowrap;
}

.prof-table td {
  padding: 13px 16px;
  border-bottom: 1px solid #f0f7f3;
  font-size: 13.5px;
  color: var(--prof-text-dark);
  vertical-align: middle;
}

.prof-table tbody tr:last-child td { border-bottom: none; }
.prof-table tbody tr:hover { background: rgba(0,166,81,.03); }

/* Score badge */
.prof-score-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 700;
}

.prof-score-badge--good { background: #dcfce7; color: #166534; }
.prof-score-badge--mid  { background: #fef9c3; color: #854d0e; }
.prof-score-badge--low  { background: #fee2e2; color: #991b1b; }

/* ── Note form ── */
.prof-note-form { display: flex; flex-direction: column; gap: 14px; }

.prof-note-textarea {
  width: 100%;
  padding: 13px 16px;
  border: 1.5px solid var(--prof-border);
  border-radius: 12px;
  font-size: 14px;
  font-family: inherit;
  background: var(--prof-off-white);
  color: var(--prof-text-dark);
  resize: vertical;
  transition: border-color .18s, box-shadow .18s;
  line-height: 1.6;
}

.prof-note-textarea:focus {
  outline: none;
  border-color: var(--prof-green);
  background: #fff;
  box-shadow: 0 0 0 4px rgba(0,166,81,.12);
}

/* ── Buttons ── */
.prof-btn {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 11px 20px;
  border-radius: 10px;
  font-size: 14px;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  border: none;
  transition: all .18s;
  align-self: flex-start;
}

.prof-btn--primary {
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  box-shadow: 0 4px 14px rgba(0,166,81,.35);
}

.prof-btn--primary:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(0,166,81,.5);
}

.prof-btn:disabled { opacity: .55; cursor: not-allowed; transform: none !important; }

/* ── Notes list ── */
.prof-notes-list { display: flex; flex-direction: column; gap: 12px; }

.prof-note-card {
  background: var(--prof-off-white);
  border: 1.5px solid var(--prof-border);
  border-left: 4px solid var(--prof-green);
  border-radius: 12px;
  padding: 16px;
  transition: box-shadow .2s;
}

.prof-note-card:hover { box-shadow: 0 4px 16px rgba(0,122,58,.1); }

.prof-note-card__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.prof-note-card__author { font-size: 13px; font-weight: 700; color: var(--prof-green-dark); }
.prof-note-card__date   { font-size: 11.5px; color: var(--prof-text-light); }
.prof-note-card__content { font-size: 13.5px; color: #4B7A62; line-height: 1.65; margin: 0; }

/* ── Coming soon ── */
.prof-coming-soon {
  background: var(--prof-white);
  border: 1.5px solid var(--prof-border);
  border-radius: 16px;
  text-align: center;
  padding: 60px 30px;
  box-shadow: var(--prof-shadow);
}

.prof-coming-soon__icon { font-size: 56px; margin-bottom: 16px; }
.prof-coming-soon h2 { color: var(--prof-text-dark); font-size: 22px; font-weight: 800; margin: 0 0 10px; }
.prof-coming-soon p { color: var(--prof-text-light); font-size: 14px; line-height: 1.7; margin: 0; }

/* ── Toast ── */
.prof-toast-wrap {
  position: fixed;
  bottom: 24px; right: 24px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  z-index: 9999;
}

.prof-toast {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 18px;
  border-radius: 12px;
  min-width: 280px; max-width: 380px;
  box-shadow: 0 8px 28px rgba(0,0,0,.15);
  animation: prof-toast-in .3s cubic-bezier(.34,1.56,.64,1);
  font-size: 13.5px;
  font-weight: 500;
}

@keyframes prof-toast-in {
  from { opacity: 0; transform: translateY(20px) scale(.95); }
  to   { opacity: 1; transform: translateY(0) scale(1); }
}

.prof-toast--success { background: #fff; border-left: 4px solid var(--prof-green); color: var(--prof-text-dark); }
.prof-toast--error   { background: #fff; border-left: 4px solid #E53935; color: var(--prof-text-dark); }
.prof-toast__icon  { font-size: 18px; flex-shrink: 0; }
.prof-toast__msg   { flex: 1; }
.prof-toast__close { background: none; border: none; cursor: pointer; color: var(--prof-text-light); font-size: 16px; padding: 0; line-height: 1; }

/* ════════════════════════════
   INVITATION CARDS (professional view)
════════════════════════════ */
.prof-inv-list { display: flex; flex-direction: column; gap: 16px; }

.prof-inv-card {
  border: 1.5px solid var(--prof-border);
  border-radius: 14px;
  overflow: hidden;
  box-shadow: var(--prof-shadow);
  background: var(--prof-white);
}

.prof-inv-card__head {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 16px 20px;
  border-bottom: 1px solid var(--prof-border);
  background: var(--prof-off-white);
}
.prof-inv-card__avatar {
  width: 46px; height: 46px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--prof-green-dark), var(--prof-green));
  color: #fff;
  font-size: 18px; font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}
.prof-inv-card__info { flex: 1; }
.prof-inv-card__info strong { display: block; font-size: 15px; font-weight: 700; color: var(--prof-text-dark); }
.prof-inv-card__info span  { font-size: 12.5px; color: var(--prof-text-light); }
.prof-inv-card__meta { display: flex; flex-direction: column; align-items: flex-end; gap: 4px; }
.prof-inv-card__children { font-size: 12.5px; font-weight: 600; color: var(--prof-green-dark); background: var(--prof-green-light); border-radius: 20px; padding: 3px 10px; }
.prof-inv-card__date { font-size: 11.5px; color: #aabfb5; }

/* Steps */
.prof-inv-steps { display: flex; flex-direction: column; gap: 8px; padding: 16px 20px; }

.prof-inv-step {
  display: flex; align-items: flex-start; gap: 14px;
  padding: 11px 14px;
  border-radius: 10px;
  background: #f8fafb;
  border: 1.5px solid #eef2ef;
}
.prof-inv-step--done {
  background: var(--prof-green-light);
  border-color: var(--prof-green-mid);
}

.prof-inv-step__circle {
  width: 28px; height: 28px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 12px; font-weight: 700;
  flex-shrink: 0;
  background: var(--prof-green);
  color: #fff;
}
.prof-inv-step__text { flex: 1; }
.prof-inv-step__label { font-size: 13px; font-weight: 600; color: var(--prof-text-dark); margin-bottom: 2px; }
.prof-inv-step__desc  { font-size: 12px; color: var(--prof-text-light); }

.prof-inv-card__actions {
  padding: 14px 20px;
  border-top: 1px solid var(--prof-border);
  background: var(--prof-off-white);
}

/* ── Responsive ── */
@media (max-width: 900px) {
  .prof-sidebar { transform: translateX(-100%); }
  .prof-main { margin-left: 0; }
  .prof-content { padding: 16px; }
  .prof-kpis { grid-template-columns: repeat(2, 1fr); }
  .prof-patient-card { flex-direction: column; }
  .prof-patient-card__grid { grid-template-columns: repeat(2, 1fr); }
  .prof-topbar { height: auto; padding: 14px 18px; flex-wrap: wrap; }
}

@media (max-width: 600px) {
  .prof-kpis { grid-template-columns: 1fr; }
  .prof-patient-card__grid { grid-template-columns: 1fr; }
}
